  1→package enrich
  2→
  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"os"
  8→
  9→	"github.com/spf13/cobra"
 10→	"github.com/usenurge/nurgesh/internal/db"
 11→	enrichpkg "github.com/usenurge/nurgesh/internal/enrich"
 12→)
 13→
 14→var enrichFormat string
 15→var enrichProspect string
 16→var enrichBatch bool
 17→var enrichLimit int
 18→var enrichStats bool
 19→
 20→var enrichCmd = &cobra.Command{
 21→	Use:   "enrich",
 22→	Short: "Enrich contacts with missing data from external providers",
 23→	Long:  "Fill missing contact fields (title, company, phone, etc.) using a waterfall of data providers.\nProviders are defined as YAML files for pluggability.",
 24→	RunE: func(cmd *cobra.Command, args []string) error {
 25→		if !enrichStats && !enrichBatch && enrichProspect == "" {
 26→			return cmd.Help()
 27→		}
 28→
 29→		d, err := db.Open()
 30→		if err != nil {
 31→			return err
 32→		}
 33→		defer d.Close()
 34→
 35→		if enrichStats {
 36→			return runEnrichStats(d)
 37→		}
 38→
 39→		if enrichProspect != "" {
 40→			return runEnrichProspect(d, enrichProspect)
 41→		}
 42→
 43→		if enrichBatch {
 44→			return runEnrichBatch(d, enrichLimit)
 45→		}
 46→
 47→		return nil
 48→	},
 49→}
 50→
 51→func runEnrichProspect(d *sql.DB, email string) error {
 52→	result, err := enrichpkg.Enrich(d, enrichpkg.EnrichRequest{ContactEmail: email})
 53→	if err != nil {
 54→		return err
 55→	}
 56→
 57→	if enrichFormat == "json" {
 58→		enc := json.NewEncoder(os.Stdout)
 59→		enc.SetIndent("", "  ")
 60→		return enc.Encode(result)
 61→	}
 62→
 63→	fmt.Printf("  Enrichment: %s\n", result.ContactEmail)
 64→	if len(result.FieldsFilled) > 0 {
 65→		fmt.Printf("  Filled:\n")
 66→		for f, v := range result.FieldsFilled {
 67→			fmt.Printf("    %s: %s\n", f, v)
 68→		}
 69→	}
 70→	if len(result.FieldsMissing) > 0 {
 71→		fmt.Printf("  Still missing: %v\n", result.FieldsMissing)
 72→	}
 73→	if len(result.ProvidersUsed) > 0 {
 74→		fmt.Printf("  Providers: %v\n", result.ProvidersUsed)
 75→	}
 76→	if result.Cached > 0 {
 77→		fmt.Printf("  Cached hits: %d\n", result.Cached)
 78→	}
 79→	if result.TotalCost > 0 {
 80→		fmt.Printf("  Est. cost: $%.4f\n", result.TotalCost)
 81→	}
 82→	return nil
 83→}
 84→
 85→func runEnrichBatch(d *sql.DB, limit int) error {
 86→	results, err := enrichpkg.BatchEnrich(d, limit)
 87→	if err != nil {
 88→		return err
 89→	}
 90→
 91→	if enrichFormat == "json" {
 92→		enc := json.NewEncoder(os.Stdout)
 93→		enc.SetIndent("", "  ")
 94→		return enc.Encode(results)
 95→	}
 96→
 97→	if len(results) == 0 {
 98→		fmt.Println("  No contacts to enrich.")
 99→		return nil
100→	}
101→
102→	totalFilled := 0
103→	totalMissing := 0
104→	totalCached := 0
105→	var totalCost float64
106→	for _, r := range results {
107→		totalFilled += len(r.FieldsFilled)
108→		totalMissing += len(r.FieldsMissing)
109→		totalCached += r.Cached
110→		totalCost += r.TotalCost
111→	}
112→
113→	fmt.Printf("  Enriched %d contact(s):\n", len(results))
114→	fmt.Printf("    Fields filled: %d\n", totalFilled)
115→	fmt.Printf("    Fields missing: %d\n", totalMissing)
116→	fmt.Printf("    Cache hits: %d\n", totalCached)
117→	if totalCost > 0 {
118→		fmt.Printf("    Est. cost: $%.4f\n", totalCost)
119→	}
120→	return nil
121→}
122→
123→func runEnrichStats(d *sql.DB) error {
124→	stats, err := enrichpkg.Stats(d)
125→	if err != nil {
126→		return err
127→	}
128→
129→	if enrichFormat == "json" {
130→		enc := json.NewEncoder(os.Stdout)
131→		enc.SetIndent("", "  ")
132→		return enc.Encode(stats)
133→	}
134→
135→	fmt.Printf("  Enrichment Coverage (%d contacts)\n", stats.TotalContacts)
136→	fmt.Printf("  ──────────────────────────────────\n")
137→	fmt.Printf("  Enriched:    %d\n", stats.Enriched)
138→	fmt.Printf("  Unenriched:  %d\n", stats.Unenriched)
139→	fmt.Println()
140→	fmt.Println("  Field Coverage:")
141→	for _, field := range enrichpkg.AllEnrichableFields() {
142→		count := stats.FieldCoverage[field]
143→		pct := 0.0
144→		if stats.TotalContacts > 0 {
145→			pct = float64(count) / float64(stats.TotalContacts) * 100
146→		}
147→		fmt.Printf("    %-15s %d (%.0f%%)\n", field, count, pct)
148→	}
149→	return nil
150→}
