152→func init() {
153→	enrichCmd.PersistentFlags().StringVar(&enrichFormat, "format", "", "Output format (json)")
154→	enrichCmd.Flags().StringVar(&enrichProspect, "prospect", "", "Enrich a single contact by email")
155→	enrichCmd.Flags().BoolVar(&enrichBatch, "batch", false, "Enrich all unenriched contacts")
