174→var dispatcherInstallCmd = &cobra.Command{
175→	Use:   "install",
176→	Short: "Generate a local cron/launchd wrapper for unattended dispatch",
177→	Long: "Writes a project-local wrapper script that runs `nurge dispatcher run --execute`\n" +
178→		"on a schedule, plus a launchd plist you can copy into LaunchAgents on macOS.",
179→	RunE: func(cmd *cobra.Command, args []string) error {
180→		if !project.IsNurgeProject(".") {
181→			return fmt.Errorf("run this from a Nurge project root")
182→		}
183→
184→		projectRoot, err := filepath.Abs(".")
185→		if err != nil {
186→			return fmt.Errorf("resolving project root: %w", err)
187→		}
188→		executablePath, err := os.Executable()
189→		if err != nil {
190→			return fmt.Errorf("resolving nurge executable: %w", err)
191→		}
192→
193→		assets, err := automation.WriteDispatcherAssets(automation.DispatcherOptions{
194→			ProjectRoot:     projectRoot,
195→			ExecutablePath:  executablePath,
196→			IntervalMinutes: dispatcherInstallIntervalMinutes,
197→			SyncReplies:     dispatcherInstallSyncReplies,
198→			TransportEmail:  dispatcherInstallTransportEmail,
199→		})
200→		if err != nil {
201→			return err
202→		}
203→
204→		if dispatcherFormat == "json" {
205→			enc := json.NewEncoder(os.Stdout)
206→			enc.SetIndent("", "  ")
207→			return enc.Encode(assets)
208→		}
209→
210→		fmt.Println("  ✓ Generated unattended dispatcher assets")
211→		fmt.Printf("    script: %s\n", assets.ScriptPath)
212→		fmt.Printf("    log: %s\n", assets.LogPath)
213→		fmt.Printf("    launchd: %s\n", assets.LaunchdPlistPath)
214→
215→		if assets.CronLine != "" {
216→			fmt.Println()
217→			fmt.Println("  Cron")
218→			fmt.Printf("    %s\n", assets.CronLine)
219→		} else {
220→			fmt.Println()
221→			fmt.Printf("  Cron\n    no exact cron expression for %d-minute intervals; use launchd or adjust manually\n", assets.IntervalMinutes)
222→		}
223→
224→		fmt.Println()
225→		fmt.Println("  macOS launchd")
226→		if assets.LaunchdInstallPath != "" {
227→			fmt.Printf("    cp %s %s\n", shellSnippet(assets.LaunchdPlistPath), shellSnippet(assets.LaunchdInstallPath))
228→			fmt.Printf("    launchctl bootout gui/$(id -u) %s 2>/dev/null || true\n", shellSnippet(assets.LaunchdInstallPath))
229→			fmt.Printf("    launchctl bootstrap gui/$(id -u) %s\n", shellSnippet(assets.LaunchdInstallPath))
230→		} else {
231→			fmt.Printf("    copy %s into ~/Library/LaunchAgents/%s.plist\n", assets.LaunchdPlistPath, assets.LaunchdLabel)
232→		}
233→
234→		fmt.Println()
235→		fmt.Println("  Note")
236→		fmt.Println("    This is local unattended execution: the terminal can be closed, but the machine must stay on and your auth must remain valid.")
237→
238→		return nil
239→	},
240→}
