  5→// Request a Unipile hosted auth link for connecting Gmail or LinkedIn
  6→export const requestConnectionLink = action({
  7→  args: {
  8→    userId: v.string(),
  9→    provider: v.string(), // GOOGLE | LINKEDIN
 10→  },
 11→  handler: async (ctx, args) => {
 12→    const apiKey = process.env.UNIPILE_API_KEY;
 13→    const apiUrl = process.env.UNIPILE_API_URL;
 14→    const convexSiteUrl = process.env.CONVEX_SITE_URL;
 15→
 16→    if (!apiKey || !apiUrl) {
 17→      throw new Error("Unipile API key or URL not configured");
 18→    }
 19→
 20→    const notifyUrl = `${convexSiteUrl}/api/unipile-account-callback`;
 21→
 22→    // expiresOn must match Unipile's strict format: YYYY-MM-DDTHH:MM:SS.sssZ
 23→    const expires = new Date(Date.now() + 30 * 60 * 1000);
 24→    const expiresOn = expires.toISOString(); // Already in correct format
 25→
 26→    const successRedirectUrl = `${convexSiteUrl}/api/connect-success`;
 27→
 28→    console.log("Unipile requestConnectionLink:", { notifyUrl, provider: args.provider, userId: args.userId, convexSiteUrl });
 29→    const resp = await fetch(`${apiUrl}/api/v1/hosted/accounts/link`, {
 30→      method: "POST",
 31→      headers: {
 32→        "X-API-KEY": apiKey,
 33→        "Content-Type": "application/json",
 34→      },
 35→      body: JSON.stringify({
 36→        type: "create",
 37→        providers: [args.provider],
 38→        api_url: apiUrl,
 39→        notify_url: notifyUrl,
 40→        success_redirect_url: successRedirectUrl,
 41→        name: `${args.userId}:${args.provider}`, // Encode userId + provider for callback
 42→        expiresOn,
 43→      }),
 44→    });
 45→
 46→    if (!resp.ok) {
 47→      const error = await resp.text();
 48→      throw new Error(`Unipile request_link failed: ${error}`);
 49→    }
 50→
 51→    const result = await resp.json();
 52→    return { url: result.url };
 53→  },
 54→});
