138→export const storeEmail = internalMutation({
139→  args: {
140→    userId: v.string(),
141→    email: v.object({
142→      externalId: v.string(),
143→      source: v.string(),
144→      direction: v.string(),
145→      threadId: v.string(),
146→      subject: v.optional(v.string()),
147→      fromEmail: v.string(),
