  1→import { v } from "convex/values";
  2→import { internalAction, internalQuery, internalMutation } from "./_generated/server";
  3→import { internal } from "./_generated/api";
  4→import {
  5→  isSuppressed,
  6→  countSendsForDay,
  7→  todayInTimezone,
  8→  withinSendWindow,
  9→} from "./helpers";
 10→
 11→const BATCH_SIZE = 10;
 12→
 13→// Email dispatch via Unipile (secondary path).
 14→// The primary EMAIL send path is now local: `nurge dispatcher run --execute`
 15→// uses Gmail API directly. This Convex action remains active for:
 16→// - LinkedIn messaging (Unipile is the only LinkedIn transport)
 17→// - Users who explicitly choose Unipile for email (multi-provider, open tracking)
 18→export const checkDueTasks = internalAction({
 19→  handler: async (ctx) => {
 20→    const now = new Date().toISOString();
 21→
 22→    const dueTasks = await ctx.runQuery(internal.dispatcher.findDueTasks, {
 23→      now,
 24→      limit: BATCH_SIZE,
 25→    });
 26→
 27→    if (dueTasks.length === 0) return;
 28→
 29→    for (const task of dueTasks) {
 30→      try {
 31→        const enrollment = await ctx.runQuery(
 32→          internal.dispatcher.getEnrollment,
 33→          { enrollmentId: task.enrollmentId }
 34→        );
 35→        if (!enrollment || enrollment.status !== "active") continue;
 36→
 37→        const suppression = await ctx.runQuery(
 38→          internal.dispatcher.checkSuppression,
 39→          { userId: task.userId, email: task.contactEmail }
 40→        );
 41→        if (suppression.suppressed) {
 42→          await ctx.runMutation(internal.dispatcher.cancelTask, {
 43→            taskId: task.externalId,
 44→            userId: task.userId,
 45→            reason: `Contact suppressed: ${suppression.reason}`,
 46→          });
 47→          continue;
 48→        }
 49→
 50→        const mailbox = await ctx.runQuery(
 51→          internal.dispatcher.getMailbox,
 52→          { mailboxId: task.mailboxId }
 53→        );
 54→        if (!mailbox || mailbox.status !== "active") continue;
 55→        if (
 56→          !withinSendWindow(
 57→            mailbox.sendWindowStartHour,
 58→            mailbox.sendWindowEndHour,
 59→            mailbox.sendWindowTimezone
 60→          )
 61→        ) {
 62→          continue;
 63→        }
 64→
 65→        const today = todayInTimezone(mailbox.sendWindowTimezone);
 66→        const sendCount = await ctx.runQuery(
 67→          internal.dispatcher.countSends,
 68→          { mailboxId: task.mailboxId, sendType: task.sendType, day: today }
 69→        );
 70→
 71→        const capMap: Record<string, number> = {
 72→          first_touch: mailbox.firstTouchDailyCap,
 73→          follow_up: mailbox.followUpDailyCap,
 74→          reply: mailbox.replyDailyCap,
 75→        };
 76→        const cap = capMap[task.sendType] || 0;
 77→        if (cap > 0 && sendCount >= cap) continue;
 78→
 79→        const draft = await ctx.runQuery(
 80→          internal.dispatcher.getDraft,
 81→          { taskId: task.externalId }
 82→        );
 83→        if (draft && draft.status === "stale") continue;
 84→
 85→        await ctx.runMutation(internal.dispatcher.claimTask, {
 86→          taskId: task.externalId,
 87→          userId: task.userId,
 88→        });
 89→
 90→        const unipileAccount = await ctx.runQuery(
 91→          internal.dispatcher.getUnipileAccount,
 92→          { userId: task.userId, provider: "GOOGLE" }
 93→        );
 94→        if (!unipileAccount) continue;
 95→
 96→        const subject = draft?.subject || task.subject || "";
 97→        const body = draft?.body || task.body || "";
 98→
 99→        await ctx.runAction(internal.send.sendViaUnipile, {
100→          userId: task.userId,
101→          taskId: task.externalId,
102→          accountId: unipileAccount.unipileAccountId,
103→          to: task.contactEmail,
104→          subject,
105→          body,
106→          replyTo: enrollment.unipileThreadProviderId || undefined,
107→        });
108→      } catch (error) {
109→        console.error(`Error processing task ${task.externalId}:`, error);
110→      }
111→    }
112→  },
113→});
114→
