 11→func EnsureMailbox(d *sql.DB, email, provider string) (*Mailbox, error) {
 12→	if email == "" {
 13→		return nil, fmt.Errorf("mailbox email is required")
 14→	}
 15→
 16→	// Check if this email already exists (update is always allowed)
 17→	existing, _ := mailboxByEmail(d, email)
 18→	if existing == nil {
 19→		// New mailbox — enforce limit
 20→		var count int
 21→		if err := d.QueryRow("SELECT COUNT(*) FROM mailboxes").Scan(&count); err != nil {
 22→			return nil, fmt.Errorf("checking mailbox count: %w", err)
 23→		}
 24→		if count >= MaxMailboxes {
 25→			return nil, fmt.Errorf("mailbox limit reached (%d). Current plan supports up to %d sending accounts", count, MaxMailboxes)
 26→		}
 27→	}
 28→
 29→	_, err := d.Exec(`
 30→		INSERT INTO mailboxes (id, email, transport_email, provider, warmup_started_at)
 31→		VALUES (?, ?, ?, ?, datetime('now'))
 32→		ON CONFLICT(email) DO UPDATE SET
 33→			provider = excluded.provider,
 34→			transport_email = CASE
 35→				WHEN mailboxes.transport_email = '' THEN excluded.transport_email
 36→				ELSE mailboxes.transport_email
 37→			END,
 38→			warmup_started_at = CASE
 39→				WHEN mailboxes.warmup_started_at = '' THEN excluded.warmup_started_at
 40→				ELSE mailboxes.warmup_started_at
 41→			END,
 42→			updated_at = datetime('now')`,
 43→		newID("mbx"), email, email, provider,
 44→	)
 45→	if err != nil {
 46→		return nil, err
 47→	}
 48→
 49→	return mailboxByEmail(d, email)
 50→}
