 52→func ListMailboxes(d *sql.DB, now time.Time) ([]MailboxStatus, error) {
 53→	if now.IsZero() {
 54→		now = time.Now()
 55→	}
 56→
 57→	rows, err := d.Query(`
 58→		SELECT
 59→			m.id, m.email, m.transport_email, m.rotation_group, m.provider, m.status, m.warmup_stage, m.warmup_started_at,
 60→			m.first_touch_daily_cap, m.follow_up_daily_cap, m.reply_daily_cap, m.min_gap_minutes,
 61→			m.send_window_start_hour, m.send_window_end_hour, m.send_window_timezone,
 62→			m.reputation_score, m.priority, m.last_used_at, m.last_bounce_at,
 63→			COALESCE(u.first_touches_sent, 0),
 64→			COALESCE(u.follow_ups_sent, 0),
 65→			COALESCE(u.replies_sent, 0)
 66→		FROM mailboxes m
 67→		LEFT JOIN mailbox_daily_usage u
 68→			ON u.mailbox_id = m.id AND u.usage_day = ?
 69→		ORDER BY m.email ASC`,
 70→		dayKey(now),
 71→	)
 72→	if err != nil {
 73→		return nil, err
 74→	}
 75→	defer rows.Close()
 76→
 77→	var result []MailboxStatus
 78→	for rows.Next() {
 79→		var m MailboxStatus
 80→		m.UsageDay = dayKey(now)
 81→		if err := rows.Scan(
 82→			&m.ID, &m.Email, &m.TransportEmail, &m.RotationGroup, &m.Provider, &m.Status, &m.WarmupStage, &m.WarmupStartedAt,
 83→			&m.FirstTouchDailyCap, &m.FollowUpDailyCap, &m.ReplyDailyCap, &m.MinGapMinutes,
 84→			&m.SendWindowStartHour, &m.SendWindowEndHour, &m.SendWindowTimezone,
 85→			&m.ReputationScore, &m.Priority, &m.LastUsedAt, &m.LastBounceAt,
 86→			&m.FirstTouchesSent, &m.FollowUpsSent, &m.RepliesSent,
 87→		); err != nil {
 88→			return nil, err
 89→		}
 90→		m.FirstTouchDailyCap, m.FollowUpDailyCap, m.ReplyDailyCap = effectiveCaps(m.Mailbox, now)
 91→		m.FirstTouchesRemaining = remaining(m.FirstTouchDailyCap, m.FirstTouchesSent)
 92→		m.FollowUpsRemaining = remaining(m.FollowUpDailyCap, m.FollowUpsSent)
 93→		m.RepliesRemaining = remaining(m.ReplyDailyCap, m.RepliesSent)
 94→		result = append(result, m)
 95→	}
 96→
 97→	return result, rows.Err()
 98→}
