100→func UpdateMailboxPolicy(d *sql.DB, mailboxEmail string, opts MailboxPolicyOptions) (*Mailbox, error) {
101→	mailbox, err := mailboxByEmail(d, mailboxEmail)
102→	if err != nil {
103→		return nil, err
104→	}
105→
106→	args := []any{}
107→	sets := []string{}
108→	if opts.Status != "" {
109→		sets = append(sets, "status = ?")
110→		args = append(args, opts.Status)
111→	}
112→	if opts.TransportEmail != "" {
113→		sets = append(sets, "transport_email = ?")
114→		args = append(args, opts.TransportEmail)
115→	}
116→	if opts.RotationGroup != "" {
117→		sets = append(sets, "rotation_group = ?")
118→		args = append(args, opts.RotationGroup)
119→	}
120→	if opts.WarmupStage != "" {
121→		sets = append(sets, "warmup_stage = ?")
122→		args = append(args, opts.WarmupStage)
123→		if strings.EqualFold(opts.WarmupStage, "warming") || strings.EqualFold(opts.WarmupStage, "ramping") {
124→			sets = append(sets, "warmup_started_at = CASE WHEN warmup_started_at = '' THEN datetime('now') ELSE warmup_started_at END")
125→		}
126→	}
127→	if opts.FirstTouchDailyCap != nil {
128→		sets = append(sets, "first_touch_daily_cap = ?")
129→		args = append(args, *opts.FirstTouchDailyCap)
130→	}
131→	if opts.FollowUpDailyCap != nil {
132→		sets = append(sets, "follow_up_daily_cap = ?")
133→		args = append(args, *opts.FollowUpDailyCap)
134→	}
135→	if opts.ReplyDailyCap != nil {
136→		sets = append(sets, "reply_daily_cap = ?")
137→		args = append(args, *opts.ReplyDailyCap)
138→	}
139→	if opts.MinGapMinutes != nil {
140→		sets = append(sets, "min_gap_minutes = ?")
141→		args = append(args, *opts.MinGapMinutes)
142→	}
143→	if opts.SendWindowStartHour != nil {
144→		sets = append(sets, "send_window_start_hour = ?")
145→		args = append(args, *opts.SendWindowStartHour)
146→	}
147→	if opts.SendWindowEndHour != nil {
148→		sets = append(sets, "send_window_end_hour = ?")
149→		args = append(args, *opts.SendWindowEndHour)
150→	}
151→	if opts.SendWindowTimezone != "" {
152→		sets = append(sets, "send_window_timezone = ?")
153→		args = append(args, opts.SendWindowTimezone)
154→	}
155→	if opts.ReputationScore != nil {
156→		sets = append(sets, "reputation_score = ?")
157→		args = append(args, *opts.ReputationScore)
158→	}
159→	if opts.Priority != nil {
160→		sets = append(sets, "priority = ?")
161→		args = append(args, *opts.Priority)
162→	}
163→	if opts.RestartWarmup {
164→		sets = append(sets, "warmup_started_at = datetime('now')")
165→	}
166→	if len(sets) == 0 {
167→		return mailbox, nil
168→	}
169→
170→	args = append(args, mailbox.ID)
171→	_, err = d.Exec(
172→		fmt.Sprintf("UPDATE mailboxes SET %s, updated_at = datetime('now') WHERE id = ?", strings.Join(sets, ", ")),
173→		args...,
174→	)
175→	if err != nil {
176→		return nil, err
177→	}
178→
179→	return mailboxByEmail(d, mailboxEmail)
180→}
