182→func CanSend(d *sql.DB, mailboxID, sendType string, now time.Time) error {
183→	sendType = NormalizeSendType(sendType)
184→	if sendType == SendTypeManual {
185→		return nil
186→	}
187→	if now.IsZero() {
188→		now = time.Now()
189→	}
190→
191→	mailbox, usage, err := mailboxAndUsage(d, mailboxID, now)
192→	if err != nil {
193→		return err
194→	}
195→	if mailbox.Status != "active" {
196→		return fmt.Errorf("mailbox %s is %s", mailbox.Email, mailbox.Status)
197→	}
198→	if mailbox.ReputationScore > 0 && mailbox.ReputationScore < 40 {
199→		return fmt.Errorf("mailbox %s reputation is too low (%d)", mailbox.Email, mailbox.ReputationScore)
200→	}
201→	if !withinSendWindow(*mailbox, now) {
202→		return fmt.Errorf("mailbox %s is outside its send window (%s %02d:00-%02d:00)", mailbox.Email, mailbox.SendWindowTimezone, mailbox.SendWindowStartHour, mailbox.SendWindowEndHour)
203→	}
204→	if mailbox.LastBounceAt != "" && sendType == SendTypeFirstTouch {
205→		if bouncedAt, err := time.Parse(time.RFC3339, mailbox.LastBounceAt); err == nil && now.UTC().Before(bouncedAt.Add(24*time.Hour)) {
206→			return fmt.Errorf("mailbox %s is cooling off after a recent bounce until %s", mailbox.Email, bouncedAt.Add(24*time.Hour).Format(time.RFC3339))
207→		}
208→	}
209→	if bounceStats, err := mailboxBounceStats(d, mailboxID, now, 14); err == nil {
210→		switch {
211→		case bounceStats.Sends >= 10 && bounceStats.BounceRate >= 0.12:
212→			return fmt.Errorf("mailbox %s bounce rate is too high (%.1f%% over %d sends in %dd)", mailbox.Email, bounceStats.BounceRate*100, bounceStats.Sends, bounceStats.WindowDays)
213→		case sendType == SendTypeFirstTouch && bounceStats.Sends >= 10 && bounceStats.BounceRate >= 0.08:
214→			return fmt.Errorf("mailbox %s first touches are paused because bounce rate reached %.1f%% over the last %d days", mailbox.Email, bounceStats.BounceRate*100, bounceStats.WindowDays)
215→		}
216→	} else {
217→		return err
218→	}
219→
220→	firstTouchCap, followUpCap, replyCap := effectiveCaps(*mailbox, now)
221→
222→	switch sendType {
223→	case SendTypeFirstTouch:
224→		if firstTouchCap > 0 && usage.FirstTouchesSent >= firstTouchCap {
225→			return fmt.Errorf("mailbox %s has reached its first-touch daily cap (%d/%d)", mailbox.Email, usage.FirstTouchesSent, firstTouchCap)
226→		}
227→	case SendTypeFollowUp:
228→		if followUpCap > 0 && usage.FollowUpsSent >= followUpCap {
229→			return fmt.Errorf("mailbox %s has reached its follow-up daily cap (%d/%d)", mailbox.Email, usage.FollowUpsSent, followUpCap)
230→		}
231→	case SendTypeReply:
232→		if replyCap > 0 && usage.RepliesSent >= replyCap {
233→			return fmt.Errorf("mailbox %s has reached its reply daily cap (%d/%d)", mailbox.Email, usage.RepliesSent, replyCap)
234→		}
235→	}
236→
237→	if mailbox.MinGapMinutes > 0 {
238→		lastSentAt, err := latestMailboxOutboundAt(d, effectiveTransportEmail(*mailbox))
239→		if err != nil {
240→			return err
241→		}
242→		if !lastSentAt.IsZero() {
243→			nextAllowed := lastSentAt.Add(time.Duration(mailbox.MinGapMinutes) * time.Minute)
244→			if now.UTC().Before(nextAllowed) {
245→				return fmt.Errorf("mailbox %s is cooling down until %s", mailbox.Email, nextAllowed.Format(time.RFC3339))
246→			}
247→		}
248→	}
249→
250→	return nil
251→}
