388→func ResolveTaskMailbox(d *sql.DB, task Task, transportEmail string, now time.Time) (*Mailbox, error) {
389→	if now.IsZero() {
390→		now = time.Now()
391→	}
392→
393→	primary, err := mailboxByID(d, task.MailboxID)
394→	if err != nil {
395→		return nil, err
396→	}
397→
398→	if transportEmail == "" {
399→		if err := CanSend(d, primary.ID, task.SendType, now); err != nil {
400→			return nil, err
401→		}
402→		return primary, nil
403→	}
404→
405→	candidates, err := rotationCandidates(d, *primary, task.SendType, transportEmail, now)
406→	if err != nil {
407→		return nil, err
408→	}
409→	if len(candidates) == 0 {
410→		return nil, fmt.Errorf("no mailbox in rotation group %q is ready for transport %s", primary.RotationGroup, transportEmail)
411→	}
412→	return candidates[0], nil
413→}
