 67→func ListDispatchTasksForTransport(d *sql.DB, opts DispatchOptions) ([]DispatchTask, error) {
 68→	if opts.Now.IsZero() {
 69→		opts.Now = time.Now()
 70→	}
 71→
 72→	tasks, err := ListTasks(d, TaskListOptions{
 73→		IncludeFuture: false,
 74→		Limit:         opts.Limit,
 75→		Now:           opts.Now,
 76→	})
 77→	if err != nil {
 78→		return nil, err
 79→	}
 80→
 81→	dispatch := make([]DispatchTask, 0, len(tasks))
 82→	for _, task := range tasks {
 83→		item := DispatchTask{Task: task, Ready: true}
 84→		if suppression, suppressed, err := IsSuppressed(d, task.ContactEmail); err != nil {
 85→			return nil, err
 86→		} else if suppressed {
 87→			item.Ready = false
 88→			item.BlockedReason = fmt.Sprintf("%s %s is suppressed (%s)", suppression.Scope, suppression.Value, suppression.Reason)
 89→			dispatch = append(dispatch, item)
 90→			continue
 91→		}
 92→
 93→		mailbox, err := ResolveTaskMailbox(d, task, opts.TransportEmail, opts.Now)
 94→		if err != nil {
 95→			item.Ready = false
 96→			item.BlockedReason = err.Error()
 97→			dispatch = append(dispatch, item)
 98→			continue
 99→		}
100→		item.SelectedMailboxID = mailbox.ID

