 17→	for _, item := range dispatch {
 18→		if !item.Ready {
 19→			continue
 20→		}
 21→
 22→		attemptedAt := time.Now()
 23→		fromAddress := strings.TrimSpace(item.TransportEmail)
 24→		if fromAddress == "" {
 25→			fromAddress = strings.TrimSpace(item.SelectedMailboxEmail)
 26→		}
 27→		if fromAddress == "" {
 28→			results = append(results, dispatcherExecutionResult{
 29→				TaskID:       item.ID,
 30→				ContactEmail: item.ContactEmail,
 31→				MailboxEmail: item.SelectedMailboxEmail,
 32→				Status:       "failed",
 33→				Error:        "no transport address available for task",
 34→			})
 35→			continue
 36→		}
 37→
 38→		sent, err := email.Send(srv, fromAddress, email.SendOptions{
 39→			To:       item.ContactEmail,
 40→			Subject:  dispatchSubject(item),
 41→			Body:     item.RenderedBody,
 42→			ThreadID: item.ThreadID,
 43→		})
 44→		if err != nil {
 45→			if markErr := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, err); markErr != nil {
 46→				return results, markErr
 47→			}
 48→			if updateErr := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusFailed, "", "", err.Error()); updateErr != nil {
 49→				return results, updateErr
 50→			}
 51→			if logErr := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
 52→				MailboxID:    item.SelectedMailboxID,
 53→				EnrollmentID: item.EnrollmentID,
 54→				TaskID:       item.ID,
 55→				ContactEmail: item.ContactEmail,
 56→				SendType:     item.SendType,
 57→				Status:       "failed",
 58→				Subject:      dispatchSubject(item),
 59→				Error:        err.Error(),
 60→				AttemptedAt:  attemptedAt,
 61→			}); logErr != nil {
 62→				return results, logErr
 63→			}
 64→			results = append(results, dispatcherExecutionResult{
 65→				TaskID:       item.ID,
 66→				ContactEmail: item.ContactEmail,
 67→				MailboxEmail: item.SelectedMailboxEmail,
 68→				Status:       "failed",
 69→				Error:        err.Error(),
 70→			})
 71→			continue
 72→		}
 73→
 74→		if err := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, nil); err != nil {
 75→			return results, err
 76→		}
 77→		if err := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
 78→			return results, err
 79→		}
 80→		if err := sequence.RecordSend(d, item.SelectedMailboxID, item.SendType, attemptedAt); err != nil {
 81→			return results, fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
 82→		}
 83→		if err := email.StoreEmail(d, &email.RawMessage{
 84→			ID:        sent.MessageID,
 85→			Source:    "gmail",
 86→			Direction: "outbound",
 87→			ThreadID:  sent.ThreadID,
 88→			Subject:   dispatchSubject(item),
 89→			FromEmail: fromAddress,
 90→			ToEmails:  cmdutil.RecipientsJSON(item.ContactEmail),
 91→			Date:      attemptedAt.UTC().Format(time.RFC3339),
 92→			Labels:    `["SENT"]`,
 93→		}); err != nil {
 94→			return results, fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
 95→		}
 96→		if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
 97→			TaskID:    item.ID,
 98→			ThreadID:  sent.ThreadID,
 99→			MessageID: sent.MessageID,
100→			MailboxID: item.SelectedMailboxID,
101→			SentAt:    attemptedAt,
102→		}); err != nil {
103→			return results, fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, item.ID, err)
104→		}
105→		if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
106→			MailboxID:    item.SelectedMailboxID,
107→			EnrollmentID: item.EnrollmentID,
108→			TaskID:       item.ID,
109→			ContactEmail: item.ContactEmail,
110→			SendType:     item.SendType,
111→			Status:       "sent",
112→			Subject:      dispatchSubject(item),
113→			MessageID:    sent.MessageID,
114→			AttemptedAt:  attemptedAt,
115→		}); err != nil {
116→			return results, err
117→		}
118→
119→		results = append(results, dispatcherExecutionResult{
120→			TaskID:       item.ID,
121→			ContactEmail: item.ContactEmail,
122→			MailboxEmail: item.SelectedMailboxEmail,
123→			MessageID:    sent.MessageID,
124→			Status:       "sent",
