 13→
 14→var tierFormat string
 15→var tierProspect string
 16→var tierBatch bool
 17→var tierLimit int
 18→var tierShow bool
 19→
 20→var tierCmd = &cobra.Command{
 21→	Use:   "tier",
 22→	Short: "Score and tier contacts based on ICP fit",
 23→	Long:  "Score contacts using ICP fit, buying triggers, intent signals, and accessibility.\nAssigns Tier 1 (>=70), Tier 2 (>=40), or Tier 3 (<40).",
 24→	RunE: func(cmd *cobra.Command, args []string) error {
 25→		if !tierShow && !tierBatch && tierProspect == "" {
 26→			return cmd.Help()
 27→		}
 28→
 29→		d, err := db.Open()
 30→		if err != nil {
 31→			return err
 32→		}
 33→		defer d.Close()
 34→
 35→		if tierShow {
 36→			return runTierShow(d)
 37→		}
 38→
 39→		if tierProspect != "" {
 40→			return runTierProspectCmd(d, tierProspect)
 41→		}
 42→
 43→		if tierBatch {
 44→			return runTierBatch(d, tierLimit)
 45→		}
 46→
 47→		return nil
 48→	},
 49→}
