 52→          id: row.externalId as string,
 53→          data,
 54→          version: row.syncVersion as number,
 55→        });
 56→      }
 57→    }
 58→
 59→    // Find the max sync version across all returned rows
 60→    let maxVersion = args.syncVersion;
 61→    for (const row of rows) {
 62→      if (row.version > maxVersion) {
 63→        maxVersion = row.version;
 64→      }
 65→    }
 66→
 67→    return { rows, sync_version: maxVersion };
 68→  },
 69→});
 70→
 71→// Push local state — CLI calls this to push SQLite → Convex
 72→export const pushLocalState = mutation({
 73→  args: {
 74→    userId: v.string(),
 75→    rows: v.array(
 76→      v.object({
 77→        table: v.string(),
 78→        id: v.string(),
 79→        data: v.any(),
 80→      })
 81→    ),
 82→  },
 83→  handler: async (ctx, args) => {
 84→    const versions: Record<string, number> = {};
 85→
 86→    // Get current max sync version
 87→    const syncState = await ctx.db
 88→      .query("syncState")
 89→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
 90→      .first();
 91→
 92→    let currentVersion = syncState?.lastSyncVersion ?? 0;
 93→
 94→    // Reverse map: snake_case → camelCase
 95→    const reverseTableMap: Record<string, string> = {};
 96→    for (const [convex, sqlite] of Object.entries(TABLE_MAP)) {
 97→      reverseTableMap[sqlite] = convex;
 98→    }
 99→
100→    for (const row of args.rows) {
101→      const convexTable = reverseTableMap[row.table] || row.table;
102→      currentVersion++;
103→
104→      // Check if row exists
105→      const existing = await ctx.db
106→        .query(convexTable as any)
107→        .withIndex("by_external_id", (q) => q.eq("externalId", row.id))
108→        .first();
109→
110→      const rowData = {
111→        ...(row.data as Record<string, any>),
112→        externalId: row.id,
113→        syncVersion: currentVersion,
114→        userId: args.userId,
115→      };
116→
117→      if (existing) {
118→        await ctx.db.patch(existing._id, rowData);
119→      } else {
120→        await ctx.db.insert(convexTable as any, rowData);
121→      }
122→
123→      versions[row.id] = currentVersion;
124→    }
125→
126→    // Update sync state
127→    if (syncState) {
128→      await ctx.db.patch(syncState._id, { lastSyncVersion: currentVersion });
129→    } else {
130→      await ctx.db.insert("syncState", {
131→        userId: args.userId,
132→        lastSyncVersion: currentVersion,
133→      });
134→    }
135→
136→    return { versions };
137→  },
138→});
139→

  1→package sync
  2→
  3→import (
  4→	"database/sql"
  5→	"fmt"
  6→	"regexp"
  7→	"time"
  8→
  9→	"github.com/usenurge/nurgesh/internal/account"
 10→)
 11→
 12→// allowedTables is the set of table names that may appear in SQL statements.
 13→// Built from executionTables at init time.
 14→var allowedTables map[string]bool
 15→
 16→// validIdentifier matches simple SQL identifiers (letters, digits, underscores).
 17→var validIdentifier = regexp.MustCompile(`^[a-zA-Z_][a-zA-Z0-9_]*$`)
 18→
 19→func init() {
 20→	allowedTables = make(map[string]bool, len(executionTables))
 21→	for _, t := range executionTables {
 22→		allowedTables[t] = true
 23→	}
 24→}
 25→
 26→// validateTableName ensures the table name is in the execution tables whitelist.
 27→func validateTableName(table string) error {
 28→	if !allowedTables[table] {
 29→		return fmt.Errorf("unknown table %q: not in allowed execution tables", table)
 30→	}
 31→	return nil
 32→}
 33→
 34→// validateColumnName ensures a column name is a safe SQL identifier.
 35→func validateColumnName(col string) error {
 36→	if !validIdentifier.MatchString(col) {
 37→		return fmt.Errorf("invalid column name %q", col)
 38→	}
 39→	return nil
 40→}
 41→
 42→// executionTables are tables where Convex is authoritative.
 43→// Pull direction: Convex -> SQLite.
 44→var executionTables = []string{
 45→	"emails",
 46→	"mailboxes",
 47→	"mailbox_send_events",
 48→	"sequence_enrollments",
 49→	"follow_up_tasks",
 50→	"suppressions",
 51→	"reply_events",
 52→	"sequence_drafts",
 53→}
 54→
 55→// localTables are tables where SQLite is authoritative.
 56→// Push direction: SQLite -> Convex.
 57→var localTables = []string{
 58→	"contacts",
 59→	"learnings",
 60→	"skill_versions",
 61→	"deals",
 62→	"context_metrics_daily",
 63→}
 64→
 65→const batchSize = 500
 66→
 67→// SyncState tracks the last sync position per direction.
 68→type SyncState struct {
 69→	LastPullVersion int64  `json:"last_pull_version"`
 70→	LastPushAt      string `json:"last_push_at"`
 71→}
 72→
 73→// Engine handles bidirectional sync between SQLite and Convex.
 74→type Engine struct {
 75→	db     *sql.DB
 76→	client *account.ConvexClient
 77→	token  string
 78→}
 79→
 80→// NewEngine creates a sync engine.
 81→func NewEngine(db *sql.DB, client *account.ConvexClient, token string) *Engine {
 82→	return &Engine{db: db, client: client, token: token}
 83→}
 84→
 85→// PullResult contains stats from a pull operation.
 86→type PullResult struct {
 87→	PreviousVersion int64
 88→	CurrentVersion  int64
 89→	TablesUpdated   int
 90→	RowsUpserted    int
 91→	TableCounts     map[string]int
 92→}
 93→
 94→// PushResult contains stats from a push operation.
 95→type PushResult struct {
 96→	TablesScanned int
 97→	RowsPushed    int
 98→}
 99→
100→// SyncResult contains stats from a full sync (pull + push).
101→type SyncResult struct {
102→	Pull PullResult
103→	Push PushResult
104→}
105→
106→// Sync performs a full sync: pull execution state, then push local state.
107→func (e *Engine) Sync() (*SyncResult, error) {
108→	pullResult, err := e.Pull()
109→	if err != nil {
110→		return nil, fmt.Errorf("pull failed: %w", err)
111→	}
112→
113→	pushResult, err := e.Push()
114→	if err != nil {
115→		return nil, fmt.Errorf("push failed: %w", err)
116→	}
117→
118→	return &SyncResult{Pull: *pullResult, Push: *pushResult}, nil
119→}
120→
121→// Pull fetches execution state from Convex and upserts into SQLite.
122→func (e *Engine) Pull() (*PullResult, error) {
123→	state, err := e.loadSyncState()
124→	if err != nil {
125→		return nil, fmt.Errorf("loading sync state: %w", err)
126→	}
127→	previousVersion := state.LastPullVersion
128→
129→	resp, err := e.client.PullExecutionState(e.token, state.LastPullVersion)
130→	if err != nil {
131→		return nil, fmt.Errorf("pulling from Convex: %w", err)
132→	}
133→
134→	result := &PullResult{
135→		PreviousVersion: previousVersion,
136→		CurrentVersion:  previousVersion,
137→		TableCounts:     make(map[string]int),
138→	}
139→	tablesUpdated := map[string]bool{}
140→
141→	for _, row := range resp.Rows {
142→		if row.Table == "mailboxes" {
143→			skip, limitErr := e.wouldExceedMailboxLimit(row.ID)
144→			if limitErr != nil {
145→				return nil, fmt.Errorf("checking mailbox limit for %s: %w", row.ID, limitErr)
146→			}
147→			if skip {
148→				continue
149→			}
150→		}
151→		if err := e.upsertRow(row); err != nil {
152→			return nil, fmt.Errorf("upserting %s/%s: %w", row.Table, row.ID, err)
153→		}
154→		result.RowsUpserted++
155→		tablesUpdated[row.Table] = true
156→		result.TableCounts[row.Table]++
157→	}
158→	result.TablesUpdated = len(tablesUpdated)
159→
160→	if resp.SyncVersion > state.LastPullVersion {
161→		state.LastPullVersion = resp.SyncVersion
162→		result.CurrentVersion = resp.SyncVersion
163→		if err := e.saveSyncState(state); err != nil {
164→			return nil, fmt.Errorf("saving sync state: %w", err)
165→		}
166→	}
167→
168→	return result, nil
169→}
170→
171→// Push sends local state changes to Convex.
172→func (e *Engine) Push() (*PushResult, error) {
173→	state, err := e.loadSyncState()
174→	if err != nil {
175→		return nil, fmt.Errorf("loading sync state: %w", err)
176→	}
177→
178→	result := &PushResult{}
179→	var allRows []account.SyncRow
180→
181→	for _, table := range localTables {
182→		rows, err := e.changedLocalRows(table, state.LastPushAt)
183→		if err != nil {
184→			return nil, fmt.Errorf("reading changed rows from %s: %w", table, err)
185→		}
186→		allRows = append(allRows, rows...)
187→		result.TablesScanned++
188→	}
189→
190→	// Also push email classifications (local authority for the classification field)
191→	classRows, err := e.changedEmailClassifications()
192→	if err != nil {
193→		return nil, fmt.Errorf("reading changed email classifications: %w", err)
194→	}
195→	allRows = append(allRows, classRows...)
196→
197→	if len(allRows) == 0 {
198→		return result, nil
199→	}
200→
201→	// Push in batches
202→	for i := 0; i < len(allRows); i += batchSize {
203→		end := i + batchSize
204→		if end > len(allRows) {
205→			end = len(allRows)
206→		}
207→		batch := allRows[i:end]
208→
209→		resp, err := e.client.PushLocalState(e.token, batch)
210→		if err != nil {
211→			return nil, fmt.Errorf("pushing batch %d-%d: %w", i, end, err)
212→		}
213→
214→		// Update local sync_version from server response
215→		for id, version := range resp.Versions {
216→			for _, row := range batch {
217→				if row.ID == id {
218→					if err := e.updateSyncVersion(row.Table, id, version); err != nil {
219→						return nil, fmt.Errorf("updating sync_version for %s/%s: %w", row.Table, id, err)
220→					}
221→					break
222→				}
223→			}
224→		}
225→		result.RowsPushed += len(batch)
226→	}
227→
228→	state.LastPushAt = time.Now().UTC().Format(time.RFC3339)
229→	if err := e.saveSyncState(state); err != nil {
230→		return nil, fmt.Errorf("saving sync state: %w", err)
231→	}
232→
233→	return result, nil
234→}
235→

  1→package sync
  2→
  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"strings"
  8→
  9→	"github.com/usenurge/nurgesh/internal/account"
 10→)
 11→
 12→// wouldExceedMailboxLimit returns true if inserting this mailbox ID would exceed the max.
 13→// Updates to existing mailboxes are always allowed.
 14→func (e *Engine) wouldExceedMailboxLimit(id string) (bool, error) {
 15→	var exists bool
 16→	err := e.db.QueryRow("SELECT EXISTS(SELECT 1 FROM mailboxes WHERE id = ?)", id).Scan(&exists)
 17→	if err != nil {
 18→		return false, err
 19→	}
 20→	if exists {
 21→		return false, nil // update, always allowed
 22→	}
 23→	var count int
 24→	err = e.db.QueryRow("SELECT COUNT(*) FROM mailboxes").Scan(&count)
 25→	if err != nil {
 26→		return false, err
 27→	}
 28→	return count >= 2, nil
 29→}
 30→
 31→// upsertRow writes a Convex row into the local SQLite table.
 32→func (e *Engine) upsertRow(row account.SyncRow) error {
 33→	if len(row.Data) == 0 {
 34→		return nil
 35→	}
 36→
 37→	if err := validateTableName(row.Table); err != nil {
 38→		return err
 39→	}
 40→
 41→	columns := []string{"id"}
 42→	placeholders := []string{"?"}
 43→	values := []any{row.ID}
 44→	updateParts := []string{}
 45→
 46→	for col, val := range row.Data {
 47→		if err := validateColumnName(col); err != nil {
 48→			return fmt.Errorf("table %s: %w", row.Table, err)
 49→		}
 50→		columns = append(columns, col)
 51→		placeholders = append(placeholders, "?")
 52→		values = append(values, val)
 53→		updateParts = append(updateParts, fmt.Sprintf("%s = excluded.%s", col, col))
 54→	}
 55→
 56→	// Always set sync_version
 57→	columns = append(columns, "sync_version")
 58→	placeholders = append(placeholders, "?")
 59→	values = append(values, row.Version)
 60→	updateParts = append(updateParts, "sync_version = excluded.sync_version")
 61→
 62→	query := fmt.Sprintf(
 63→		"INSERT INTO %s (%s) VALUES (%s) ON CONFLICT(id) DO UPDATE SET %s",
 64→		row.Table,
 65→		strings.Join(columns, ", "),
 66→		strings.Join(placeholders, ", "),
 67→		strings.Join(updateParts, ", "),
 68→	)
 69→
 70→	_, err := e.db.Exec(query, values...)
 71→	return err
 72→}
 73→
 74→// changedLocalRows returns rows from a local-state table changed since lastPushAt.
 75→func (e *Engine) changedLocalRows(table, lastPushAt string) ([]account.SyncRow, error) {
 76→	var rows []account.SyncRow
 77→
 78→	query := fmt.Sprintf("SELECT * FROM %s", table)
 79→	args := []any{}
 80→	if lastPushAt != "" {
 81→		query += " WHERE updated_at > ?"
 82→		args = append(args, lastPushAt)
 83→	}
 84→
 85→	sqlRows, err := e.db.Query(query, args...)
 86→	if err != nil {
 87→		return nil, err
 88→	}
 89→	defer sqlRows.Close()
 90→
 91→	cols, err := sqlRows.Columns()
 92→	if err != nil {
 93→		return nil, err
 94→	}
 95→
 96→	for sqlRows.Next() {
 97→		values := make([]any, len(cols))
 98→		ptrs := make([]any, len(cols))
 99→		for i := range values {
100→			ptrs[i] = &values[i]
101→		}
102→		if err := sqlRows.Scan(ptrs...); err != nil {
103→			return nil, err
104→		}
105→
106→		data := map[string]any{}
107→		var id string
108→		for i, col := range cols {
109→			if col == "id" {
110→				id = fmt.Sprintf("%v", values[i])
111→			}
112→			if col == "sync_version" {
113→				continue // don't push sync_version back
114→			}
115→			data[col] = values[i]
116→		}
117→
118→		rows = append(rows, account.SyncRow{
119→			Table: table,
120→			ID:    id,
121→			Data:  data,
122→		})
123→	}
124→
125→	return rows, sqlRows.Err()
126→}
127→
128→// changedEmailClassifications returns all classified emails for push.
129→// Emails lack updated_at so all are pushed each time -- idempotent on Convex side.
130→func (e *Engine) changedEmailClassifications() ([]account.SyncRow, error) {
131→	sqlRows, err := e.db.Query(`SELECT id, class, class_confidence, classified_by FROM emails WHERE class != 'unclassified'`)
132→	if err != nil {
133→		return nil, err
134→	}
135→	defer sqlRows.Close()
136→
137→	var rows []account.SyncRow
138→	for sqlRows.Next() {
139→		var id, class, classifiedBy string
140→		var confidence float64
141→		if err := sqlRows.Scan(&id, &class, &confidence, &classifiedBy); err != nil {
142→			return nil, err
143→		}
144→
145→		rows = append(rows, account.SyncRow{
146→			Table: "emails",
147→			ID:    id,
148→			Data: map[string]any{
149→				"class":            class,
150→				"class_confidence": confidence,
151→				"classified_by":    classifiedBy,
152→			},
153→		})
154→	}
155→
156→	return rows, sqlRows.Err()
157→}
158→
159→// updateSyncVersion sets the sync_version for a specific row.
160→func (e *Engine) updateSyncVersion(table, id string, version int64) error {
161→	query := fmt.Sprintf("UPDATE %s SET sync_version = ? WHERE id = ?", table)
162→	_, err := e.db.Exec(query, version, id)
163→	return err
164→}
165→
166→const syncStateKey = "_sync_state"
167→
168→// loadSyncState reads the sync cursor from a local config-like store.
169→func (e *Engine) loadSyncState() (*SyncState, error) {
170→	// Store sync state in a simple key-value row in connectors table (reusing existing table)
171→	var data string
172→	err := e.db.QueryRow(
173→		`SELECT sync_cursor FROM connectors WHERE id = ?`, syncStateKey,
174→	).Scan(&data)
175→	if err == sql.ErrNoRows {
176→		return &SyncState{}, nil
177→	}
178→	if err != nil {
179→		return nil, err
180→	}
181→
182→	var state SyncState
183→	if err := json.Unmarshal([]byte(data), &state); err != nil {
184→		return &SyncState{}, nil
185→	}
186→	return &state, nil
187→}
188→
189→// saveSyncState persists the sync cursor.
190→func (e *Engine) saveSyncState(state *SyncState) error {
191→	data, err := json.Marshal(state)
192→	if err != nil {
193→		return err
194→	}
195→
196→	_, err = e.db.Exec(`
197→		INSERT INTO connectors (id, type, sync_cursor)
198→		VALUES (?, 'sync', ?)
199→		ON CONFLICT(id) DO UPDATE SET sync_cursor = excluded.sync_cursor`,
200→		syncStateKey, string(data),
201→	)
202→	return err
203→}
