 68→// openSessionDB reads hook stdin, opens the DB, and ensures session tables.
 69→// Returns (nil, nil, nil) when the hook should silently no-op.
 70→func openSessionDB() (*sql.DB, *session.HookInput, error) {
 71→	input, err := session.ReadStdin()
 72→	if err != nil || input == nil || input.SessionID == "" {
 73→		return nil, nil, nil
 74→	}
 75→	if !db.Exists() {
 76→		return nil, nil, nil
 77→	}
 78→	d, err := db.Open()
 79→	if err != nil {
 80→		return nil, nil, nil
 81→	}
 82→	return d, input, nil
 83→}
