 90→	}
 91→	defer d.Close()
 92→
 93→	session.AddEvent(d, input.SessionID, "prompt", input)
 94→	session.Logger().Info("prompt", "session_id", input.SessionID)
 95→	session.FlushLog()
 96→	return nil
