 99→// runStop captures a stop event and creates a checkpoint.
100→func runStop() error {
101→	d, input, _ := openSessionDB()
102→	if d == nil {
103→		return nil
104→	}
105→	defer d.Close()
106→
107→	session.AddEvent(d, input.SessionID, "stop", input)
108→	if len(input.ModifiedFiles) > 0 {
109→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
110→	}
111→
112→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
113→	session.FlushLog()
114→	return nil
