124→// listUndistilledLearnings returns learnings that have not yet been distilled.
125→func listUndistilledLearnings(db *sql.DB) ([]Learning, error) {
126→	rows, err := db.Query(`
127→		SELECT id, type, content, source_session, created_at
128→		FROM learnings
129→		WHERE distilled_at IS NULL OR distilled_at = ''
130→		ORDER BY created_at ASC`)
131→	if err != nil {
132→		return nil, err
133→	}
134→	defer rows.Close()
135→
136→	var learnings []Learning
137→	for rows.Next() {
138→		var l Learning
139→		if err := rows.Scan(&l.ID, &l.Type, &l.Content, &l.SourceSession, &l.CreatedAt); err != nil {
140→			return nil, err
141→		}
142→		learnings = append(learnings, l)
143→	}
144→	return learnings, rows.Err()
145→}
