 36→func RemoveSuppression(d *sql.DB, scope, value string) error {
 37→	scope = normalizeSuppressionScope(scope)
 38→	value = normalizeSuppressionValue(scope, value)
 39→	_, err := d.Exec(`DELETE FROM suppressions WHERE scope = ? AND value = ?`, scope, value)
 40→	return err
 41→}
