 43→func ListSuppressions(d *sql.DB, scope string, limit int) ([]Suppression, error) {
 44→	query := `SELECT id, scope, value, reason, source, created_at FROM suppressions`
 45→	var args []any
 46→	if scope != "" {
 47→		query += ` WHERE scope = ?`
 48→		args = append(args, normalizeSuppressionScope(scope))
 49→	}
 50→	query += ` ORDER BY created_at DESC`
 51→	if limit > 0 {
 52→		query += fmt.Sprintf(" LIMIT %d", limit)
 53→	}
 54→
 55→	rows, err := d.Query(query, args...)
 56→	if err != nil {
 57→		return nil, err
 58→	}
 59→	defer rows.Close()
 60→
 61→	var suppressions []Suppression
 62→	for rows.Next() {
 63→		var item Suppression
 64→		if err := rows.Scan(&item.ID, &item.Scope, &item.Value, &item.Reason, &item.Source, &item.CreatedAt); err != nil {
 65→			return nil, err
 66→		}
 67→		suppressions = append(suppressions, item)
 68→	}
 69→	return suppressions, rows.Err()
 70→}
