 72→func IsSuppressed(d *sql.DB, email string) (*Suppression, bool, error) {
 73→	email = normalizeSuppressionValue("email", email)
 74→	if email == "" {
 75→		return nil, false, nil
 76→	}
 77→
 78→	if suppression, err := suppressionByScopeValue(d, "email", email); err == nil {
 79→		return suppression, true, nil
 80→	} else if !isNotFound(err) {
