 97→func suppressionByScopeValue(d *sql.DB, scope, value string) (*Suppression, error) {
 98→	row := d.QueryRow(`SELECT id, scope, value, reason, source, created_at FROM suppressions WHERE scope = ? AND value = ?`, scope, value)
 99→	var item Suppression
100→	if err := row.Scan(&item.ID, &item.Scope, &item.Value, &item.Reason, &item.Source, &item.CreatedAt); err != nil {
101→		if err == sql.ErrNoRows {
102→			return nil, fmt.Errorf("suppression %s:%s not found", scope, value)
103→		}
104→		return nil, err
105→	}
106→	return &item, nil
107→}
