199→		) AND status = ?`,
200→		TaskStatusCanceled, statusReason, normalizedContact, TaskStatusOpen,
201→	)
202→	if err != nil {
203→		return nil, err
204→	}
205→
206→	if classification == "not_interested" || classification == "unsubscribe" || classification == "bounced" {
207→		if _, err := tx.Exec(`
208→			INSERT INTO suppressions (id, scope, value, reason, source)
209→			VALUES (?, 'email', ?, ?, 'reply')
210→			ON CONFLICT(scope, value) DO UPDATE SET reason = excluded.reason, source = excluded.source`,
211→			newID("sup"), normalizedContact, statusReason,
212→		); err != nil {
213→			return nil, err
214→		}
215→	}
