327→func normalizeReplyClassification(classification string) string {
328→	switch strings.ToLower(strings.TrimSpace(classification)) {
329→	case "interested", "positive":
330→		return "interested"
331→	case "bounce", "bounced", "hard_bounce", "hard-bounce":
332→		return "bounced"
333→	case "unsubscribe", "opt_out", "opt-out":
334→		return "unsubscribe"
335→	case "not_interested", "negative":
336→		return "not_interested"
337→	case "out_of_office", "ooo", "away":
338→		return "out_of_office"
339→	case "referral":
340→		return "referral"
341→	default:
342→		return "replied"
343→	}
344→}
345→
346→func replyStatus(classification string) string {
347→	switch classification {
348→	case "bounced", "unsubscribe", "not_interested":
349→		return "closed"
350→	default:
351→		return "open"
352→	}
353→}
