  4→/**
  5→ * Gmail Pub/Sub webhook handler.
  6→ *
  7→ * Gmail pushes notifications to a Google Cloud Pub/Sub topic, which forwards
  8→ * them to this endpoint. The notification payload contains only the user's
  9→ * email address and a historyId -- no email content ever flows through here.
 10→ *
 11→ * On receiving a notification, we mark the user as "needs sync" so the next
 12→ * `nurge sync` call knows to pull changes via history.list.
 13→ */
 14→export const gmailPubSubWebhook = httpAction(async (ctx, request) => {
 15→  try {
 16→    const payload = await request.json();
 17→
 18→    // Pub/Sub wraps the data in a message envelope
 19→    const message = payload.message;
 20→    if (!message || !message.data) {
 21→      return new Response("Missing message data", { status: 400 });
 22→    }
 23→
 24→    // Decode base64 payload: { emailAddress: string, historyId: number }
 25→    const decoded = atob(message.data);
 26→    const data = JSON.parse(decoded);
 27→
 28→    const emailAddress = data.emailAddress;
 29→    const historyId = String(data.historyId);
 30→
 31→    if (!emailAddress) {
 32→      return new Response("Missing emailAddress in notification", { status: 400 });
 33→    }
 34→
 35→    await ctx.runMutation(internal.gmailWebhook.markPendingSync, {
 36→      email: emailAddress,
 37→      historyId,
 38→    });
 39→
 40→    // Always return 200 to acknowledge -- otherwise Pub/Sub retries
 41→    return new Response("OK", { status: 200 });
 42→  } catch (error: any) {
 43→    console.error("Gmail Pub/Sub webhook error:", error);
 44→    // Return 200 even on error to prevent Pub/Sub retry storms.
 45→    // The notification will be picked up on the next polling sync.
 46→    return new Response("OK", { status: 200 });
 47→  }
 48→});
 49→
 50→/**
 51→ * Mark a user's Gmail as needing sync after a Pub/Sub notification.
 52→ */
 53→export const markPendingSync = internalMutation({
 54→  args: {
 55→    email: v.string(),
 56→    historyId: v.string(),
 57→  },
 58→  handler: async (ctx, args) => {
 59→    const existing = await ctx.db
 60→      .query("gmailWatchState")
 61→      .withIndex("by_email", (q) => q.eq("email", args.email))
 62→      .first();
 63→
 64→    if (existing) {
 65→      await ctx.db.patch(existing._id, {
 66→        historyId: args.historyId,
 67→        pendingSync: true,
 68→        lastNotifiedAt: new Date().toISOString(),
 69→      });
 70→    } else {
 71→      // First notification for this email -- create the watch state.
 72→      // The userId will be empty until the CLI registers via upsertWatchState.
 73→      await ctx.db.insert("gmailWatchState", {
 74→        userId: "",
 75→        email: args.email,
 76→        historyId: args.historyId,
 77→        watchExpiry: "",
 78→        pendingSync: true,
 79→        lastNotifiedAt: new Date().toISOString(),
 80→      });
 81→    }
 82→  },
 83→});
 84→
 85→/**
 86→ * Register or update a Gmail watch state (called from CLI after users.watch()).
 87→ */
 88→export const upsertWatchState = internalMutation({
 89→  args: {
 90→    userId: v.string(),
 91→    email: v.string(),
 92→    historyId: v.string(),
 93→    watchExpiry: v.string(),
 94→  },
 95→  handler: async (ctx, args) => {
 96→    const existing = await ctx.db
 97→      .query("gmailWatchState")
 98→      .withIndex("by_email", (q) => q.eq("email", args.email))
 99→      .first();
100→
101→    if (existing) {
102→      await ctx.db.patch(existing._id, {
103→        userId: args.userId,
104→        historyId: args.historyId,
105→        watchExpiry: args.watchExpiry,
106→        pendingSync: false,
107→      });
108→    } else {
109→      await ctx.db.insert("gmailWatchState", {
110→        userId: args.userId,
111→        email: args.email,
112→        historyId: args.historyId,
113→        watchExpiry: args.watchExpiry,
114→        pendingSync: false,
115→      });
116→    }
117→  },
118→});
