  9→// EngagementEvent represents a tracked engagement signal for a sequence step.
 10→type EngagementEvent struct {
 11→	ID           int    `json:"id"`
 12→	EnrollmentID string `json:"enrollment_id"`
 13→	StepNumber   int    `json:"step_number"`
 14→	EventType    string `json:"event_type"` // open, click, reply, bounce, ooo, unsubscribe
 15→	EventData    string `json:"event_data"` // JSON
 16→	OccurredAt   string `json:"occurred_at"`
 17→}
 18→
 19→// EngagementSummary aggregates engagement counts per step for an enrollment.
 20→type EngagementSummary struct {
 21→	EnrollmentID string                   `json:"enrollment_id"`
 22→	TotalEvents  int                      `json:"total_events"`
 23→	ByType       map[string]int           `json:"by_type"`
 24→	ByStep       map[int]*StepEngagement  `json:"by_step"`
 25→}
 26→
 27→// StepEngagement holds per-step engagement counts.
 28→type StepEngagement struct {
 29→	StepNumber int            `json:"step_number"`
 30→	Opens      int            `json:"opens"`
 31→	Clicks     int            `json:"clicks"`
 32→	Replies    int            `json:"replies"`
 33→	Bounces    int            `json:"bounces"`
 34→	OOOs       int            `json:"ooos"`
 35→	Total      int            `json:"total"`
 36→}
 37→
 38→// validEngagementTypes are the allowed event types.
 39→var validEngagementTypes = map[string]bool{
 40→	"open":        true,
 41→	"click":       true,
 42→	"reply":       true,
 43→	"bounce":      true,
 44→	"ooo":         true,
 45→	"unsubscribe": true,
 46→}
 47→
 48→// RecordEngagement inserts an engagement event for a sequence enrollment step.
 49→func RecordEngagement(d *sql.DB, enrollmentID string, step int, eventType, eventData, occurredAt string) error {
 50→	enrollmentID = strings.TrimSpace(enrollmentID)
 51→	if enrollmentID == "" {
 52→		return fmt.Errorf("enrollment ID is required")
 53→	}
 54→	eventType = strings.TrimSpace(strings.ToLower(eventType))
 55→	if !validEngagementTypes[eventType] {
 56→		return fmt.Errorf("invalid event type %q; valid types: open, click, reply, bounce, ooo, unsubscribe", eventType)
 57→	}
 58→	if step < 1 {
 59→		return fmt.Errorf("step number must be >= 1")
 60→	}
 61→	if strings.TrimSpace(occurredAt) == "" {
 62→		return fmt.Errorf("occurred_at is required")
 63→	}
 64→	if strings.TrimSpace(eventData) == "" {
 65→		eventData = "{}"
 66→	}
 67→
 68→	_, err := d.Exec(`
 69→		INSERT INTO engagement_events (enrollment_id, step_number, event_type, event_data, occurred_at)
 70→		VALUES (?, ?, ?, ?, ?)`,
 71→		enrollmentID, step, eventType, eventData, occurredAt,
 72→	)
 73→	if err != nil {
 74→		return fmt.Errorf("recording engagement event: %w", err)
 75→	}
 76→	return nil
 77→}
 78→
 79→// ListEngagement returns all engagement events for an enrollment, ordered by occurred_at.
 80→func ListEngagement(d *sql.DB, enrollmentID string) ([]EngagementEvent, error) {
 81→	enrollmentID = strings.TrimSpace(enrollmentID)
 82→	if enrollmentID == "" {
 83→		return nil, fmt.Errorf("enrollment ID is required")
 84→	}
 85→
 86→	rows, err := d.Query(`
 87→		SELECT id, enrollment_id, step_number, event_type, event_data, occurred_at
 88→		FROM engagement_events
 89→		WHERE enrollment_id = ?
 90→		ORDER BY occurred_at ASC, id ASC`,
 91→		enrollmentID,
 92→	)
 93→	if err != nil {
 94→		return nil, fmt.Errorf("listing engagement events: %w", err)
 95→	}
 96→	defer rows.Close()
 97→
 98→	var events []EngagementEvent
 99→	for rows.Next() {
100→		var e EngagementEvent
101→		if err := rows.Scan(&e.ID, &e.EnrollmentID, &e.StepNumber, &e.EventType, &e.EventData, &e.OccurredAt); err != nil {
102→			return nil, fmt.Errorf("scanning engagement event: %w", err)
103→		}
104→		events = append(events, e)
105→	}
106→	return events, rows.Err()
107→}
108→
109→// EngagementSummaryForEnrollment returns aggregated engagement counts per step.
110→func EngagementSummaryForEnrollment(d *sql.DB, enrollmentID string) (*EngagementSummary, error) {
111→	events, err := ListEngagement(d, enrollmentID)
112→	if err != nil {
113→		return nil, err
114→	}
115→
116→	summary := &EngagementSummary{
117→		EnrollmentID: enrollmentID,
118→		ByType:       make(map[string]int),
119→		ByStep:       make(map[int]*StepEngagement),
120→	}
121→
122→	for _, e := range events {
123→		summary.TotalEvents++
124→		summary.ByType[e.EventType]++
125→
126→		step, ok := summary.ByStep[e.StepNumber]
127→		if !ok {
128→			step = &StepEngagement{StepNumber: e.StepNumber}
129→			summary.ByStep[e.StepNumber] = step
130→		}
131→		step.Total++
132→
133→		switch e.EventType {
134→		case "open":
135→			step.Opens++
136→		case "click":
137→			step.Clicks++
138→		case "reply":
139→			step.Replies++
140→		case "bounce":
141→			step.Bounces++
142→		case "ooo":
143→			step.OOOs++
144→		}
145→	}
146→
147→	return summary, nil
148→}
