 10→func ListTasks(d *sql.DB, opts TaskListOptions) ([]Task, error) {
 11→	if opts.Now.IsZero() {
 12→		opts.Now = time.Now()
 13→	}
 14→
 15→	query := `
 16→		SELECT
 17→			t.id, t.enrollment_id, e.sequence_name, e.campaign_name, t.mailbox_id, m.email,
 18→			t.contact_email, t.subject, t.thread_id, t.step_number, t.step_name,
 19→			t.send_type, t.status, t.due_at, t.body, t.send_status, t.last_attempt_at, t.last_error, t.attempt_count
 20→		FROM follow_up_tasks t
 21→		JOIN sequence_enrollments e ON e.id = t.enrollment_id
 22→		JOIN mailboxes m ON m.id = t.mailbox_id
 23→		WHERE t.status = ? AND e.status = ?`
 24→	args := []any{TaskStatusOpen, StatusActive}
 25→
 26→	if !opts.IncludeFuture {
 27→		query += " AND t.due_at <= ?"
 28→		args = append(args, opts.Now.UTC().Format(time.RFC3339))
 29→	}
 30→
 31→	query += " ORDER BY t.due_at ASC"
 32→	if opts.Limit > 0 {
 33→		query += fmt.Sprintf(" LIMIT %d", opts.Limit)
 34→	}
 35→
 36→	rows, err := d.Query(query, args...)
 37→	if err != nil {
 38→		return nil, err
 39→	}
 40→	defer rows.Close()
 41→
 42→	var tasks []Task
 43→	for rows.Next() {
 44→		var task Task
 45→		if err := rows.Scan(
 46→			&task.ID, &task.EnrollmentID, &task.SequenceName, &task.CampaignName, &task.MailboxID,
 47→			&task.MailboxEmail, &task.ContactEmail, &task.Subject, &task.ThreadID,
 48→			&task.StepNumber, &task.StepName, &task.SendType, &task.Status, &task.DueAt,
 49→			&task.Body, &task.SendStatus, &task.LastAttemptAt, &task.LastError, &task.AttemptCount,
 50→		); err != nil {
 51→			return nil, err
 52→		}
 53→		task.DaysUntilDue = daysUntil(task.DueAt, opts.Now)
 54→		tasks = append(tasks, task)
 55→	}
 56→
 57→	return tasks, rows.Err()
 58→}
