  1→package email
  2→
  3→import (
  4→	"database/sql"
  5→	"strings"
  6→	"time"
  7→
  8→	gm "google.golang.org/api/gmail/v1"
  9→
 10→	"github.com/usenurge/nurgesh/internal/sequence"
 11→)
 12→
 13→type ReplySyncResult struct {
 14→	ThreadsScanned  int `json:"threads_scanned"`
 15→	MessagesScanned int `json:"messages_scanned"`
 16→	RepliesRecorded int `json:"replies_recorded"`
 17→	Paused          int `json:"paused"`
 18→	Stopped         int `json:"stopped"`
 19→}
 20→
 21→func SyncReplies(srv *gm.Service, d *sql.DB, mailboxEmail string, now time.Time) (*ReplySyncResult, error) {
 22→	if now.IsZero() {
 23→		now = time.Now()
 24→	}
 25→
 26→	enrollments, err := sequence.ListEnrollments(d, sequence.StatusActive, 0)
 27→	if err != nil {
 28→		return nil, err
 29→	}
 30→
 31→	result := &ReplySyncResult{}
 32→	for _, enrollment := range enrollments {
 33→		if enrollment.ThreadID == "" {
 34→			continue
 35→		}
 36→		if mailboxEmail != "" && !strings.EqualFold(mailboxEmail, enrollment.MailboxEmail) {
 37→			continue
 38→		}
 39→
 40→		thread, err := srv.Users.Threads.Get("me", enrollment.ThreadID).Format("metadata").
 41→			MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
 42→		if err != nil {
 43→			return nil, err
 44→		}
 45→		result.ThreadsScanned++
 46→
 47→		watermark := latestKnownThreadTime(enrollment)
 48→		for i := 0; i < len(thread.Messages); i++ {
 49→			result.MessagesScanned++
 50→			raw := parseMessage(thread.Messages[i])
 51→			raw.Direction = inferDirection(raw, enrollment.MailboxEmail)
 52→			if raw.Direction != "inbound" {
 53→				continue
 54→			}
 55→
 56→			occurredAt, ok := parseStoredEmailTime(raw.Date)
 57→			if !ok {
 58→				continue
 59→			}
 60→			if !watermark.IsZero() && !occurredAt.After(watermark) {
 61→				continue
 62→			}
 63→
 64→			raw.ThreadID = enrollment.ThreadID
 65→			raw.Direction = "inbound"
 66→			if err := StoreEmail(d, raw); err != nil {
 67→				return nil, err
 68→			}
 69→
 70→			reply, err := sequence.RecordReply(d, sequence.ReplyOptions{
 71→				EnrollmentID:   enrollment.ID,
 72→				MailboxID:      enrollment.MailboxID,
 73→				ThreadID:       enrollment.ThreadID,
 74→				MessageID:      raw.ID,
 75→				ContactEmail:   raw.FromEmail,
 76→				Classification: classifyReply(raw.FromEmail, raw.Subject, raw.Snippet),
 77→				Subject:        raw.Subject,
 78→				Snippet:        raw.Snippet,
 79→				OccurredAt:     occurredAt,
 80→			})
 81→			if err != nil {
 82→				return nil, err
 83→			}
 84→
 85→			result.RepliesRecorded++
 86→			if reply.Classification == "not_interested" || reply.Classification == "unsubscribe" || reply.Classification == "bounced" {
 87→				result.Stopped++
 88→			} else {
 89→				result.Paused++
 90→			}
 91→		}
 92→	}
 93→
 94→	return result, nil
 95→}
 96→
 97→func classifyReply(fromEmail, subject, snippet string) string {
 98→	text := strings.ToLower(strings.TrimSpace(fromEmail) + "\n" + subject + "\n" + snippet)
 99→	switch {
100→	case containsAny(text, "mailer-daemon", "postmaster", "delivery status notification", "undeliverable", "message blocked", "delivery has failed"):
101→		return "bounced"
102→	case containsAny(text, "out of office", "out-of-office", "automatic reply", "auto-reply", "ooo", "away until"):
103→		return "out_of_office"
104→	case containsAny(text, "unsubscribe", "stop emailing", "do not contact"):
105→		return "unsubscribe"
106→	case containsAny(text, "not interested", "no interest", "no thanks", "remove me"):
107→		return "not_interested"
108→	case containsAny(text, "yes", "interested", "sounds good", "let's chat", "let us chat", "worth a look", "happy to talk"):
109→		return "interested"
110→	case containsAny(text, "reach out to", "talk to", "speak with", "contact ") && strings.Contains(text, "@"):
111→		return "referral"
112→	default:
113→		return "replied"
114→	}
115→}
116→
117→func latestKnownThreadTime(enrollment sequence.Enrollment) time.Time {
118→	candidates := []string{enrollment.LastReplyAt, enrollment.LastSentAt}
119→	for _, candidate := range candidates {
120→		if candidate == "" {
121→			continue
122→		}
123→		if ts, err := time.Parse(time.RFC3339, candidate); err == nil {
124→			return ts.UTC()
125→		}
126→	}
127→	return time.Time{}
128→}
129→
130→func inferDirection(message *RawMessage, mailboxEmail string) string {
131→	if mailboxEmail != "" && strings.EqualFold(strings.TrimSpace(message.FromEmail), strings.TrimSpace(mailboxEmail)) {
132→		return "outbound"
133→	}
134→	return "inbound"
135→}
136→
137→func containsAny(text string, needles ...string) bool {
138→	for _, needle := range needles {
139→		if strings.Contains(text, needle) {
140→			return true
141→		}
142→	}
143→	return false
144→}
