 11→func AddSuppression(d *sql.DB, scope, value, reason, source string) (*Suppression, error) {
 12→	scope = normalizeSuppressionScope(scope)
 13→	value = normalizeSuppressionValue(scope, value)
 14→	if value == "" {
 15→		return nil, fmt.Errorf("suppression value is required")
 16→	}
 17→	if source == "" {
 18→		source = "manual"
 19→	}
 20→
 21→	_, err := d.Exec(`
 22→		INSERT INTO suppressions (id, scope, value, reason, source)
 23→		VALUES (?, ?, ?, ?, ?)
 24→		ON CONFLICT(scope, value) DO UPDATE SET
 25→			reason = excluded.reason,
 26→			source = excluded.source`,
 27→		newID("sup"), scope, value, reason, source,
 28→	)
 29→	if err != nil {
 30→		return nil, err
 31→	}
 32→
 33→	return suppressionByScopeValue(d, scope, value)
 34→}
 35→
 36→func RemoveSuppression(d *sql.DB, scope, value string) error {
 37→	scope = normalizeSuppressionScope(scope)
 38→	value = normalizeSuppressionValue(scope, value)
 39→	_, err := d.Exec(`DELETE FROM suppressions WHERE scope = ? AND value = ?`, scope, value)
 40→	return err
 41→}
 42→
 43→func ListSuppressions(d *sql.DB, scope string, limit int) ([]Suppression, error) {
 44→	query := `SELECT id, scope, value, reason, source, created_at FROM suppressions`
 45→	var args []any
 46→	if scope != "" {
 47→		query += ` WHERE scope = ?`
 48→		args = append(args, normalizeSuppressionScope(scope))
 49→	}
 50→	query += ` ORDER BY created_at DESC`
 51→	if limit > 0 {
 52→		query += fmt.Sprintf(" LIMIT %d", limit)
 53→	}
 54→
 55→	rows, err := d.Query(query, args...)
 56→	if err != nil {
 57→		return nil, err
 58→	}
 59→	defer rows.Close()
 60→
 61→	var suppressions []Suppression
 62→	for rows.Next() {
 63→		var item Suppression
 64→		if err := rows.Scan(&item.ID, &item.Scope, &item.Value, &item.Reason, &item.Source, &item.CreatedAt); err != nil {
 65→			return nil, err
 66→		}
 67→		suppressions = append(suppressions, item)
 68→	}
 69→	return suppressions, rows.Err()
 70→}
