 72→func IsSuppressed(d *sql.DB, email string) (*Suppression, bool, error) {
 73→	email = normalizeSuppressionValue("email", email)
 74→	if email == "" {
 75→		return nil, false, nil
 76→	}
 77→
 78→	if suppression, err := suppressionByScopeValue(d, "email", email); err == nil {
 79→		return suppression, true, nil
 80→	} else if !isNotFound(err) {
 81→		return nil, false, err
 82→	}
 83→
 84→	domain := domainFromEmail(email)
 85→	if domain == "" {
 86→		return nil, false, nil
 87→	}
 88→	if suppression, err := suppressionByScopeValue(d, "domain", domain); err == nil {
 89→		return suppression, true, nil
 90→	} else if !isNotFound(err) {
 91→		return nil, false, err
 92→	}
 93→
 94→	return nil, false, nil
 95→}
 96→
 97→func suppressionByScopeValue(d *sql.DB, scope, value string) (*Suppression, error) {
 98→	row := d.QueryRow(`SELECT id, scope, value, reason, source, created_at FROM suppressions WHERE scope = ? AND value = ?`, scope, value)
 99→	var item Suppression
100→	if err := row.Scan(&item.ID, &item.Scope, &item.Value, &item.Reason, &item.Source, &item.CreatedAt); err != nil {
101→		if err == sql.ErrNoRows {
102→			return nil, fmt.Errorf("suppression %s:%s not found", scope, value)
103→		}
104→		return nil, err
105→	}
106→	return &item, nil
107→}
108→
109→func normalizeSuppressionScope(scope string) string {
110→	scope = strings.ToLower(strings.TrimSpace(scope))
111→	switch scope {
112→	case "domain":
113→		return "domain"
114→	default:
115→		return "email"
116→	}
117→}
118→
119→func normalizeSuppressionValue(scope, value string) string {
120→	value = strings.ToLower(strings.TrimSpace(value))
121→	if scope == "domain" {
122→		value = strings.TrimPrefix(value, "@")
123→	}
124→	return value
125→}
