127→func RecordReply(d *sql.DB, opts ReplyOptions) (*ReplyEvent, error) {
128→	if opts.EnrollmentID == "" {
129→		return nil, fmt.Errorf("enrollment ID is required")
130→	}
131→	if opts.MessageID == "" {
132→		return nil, fmt.Errorf("message ID is required")
133→	}
134→	if opts.OccurredAt.IsZero() {
135→		opts.OccurredAt = time.Now()
136→	}
137→	enrollment, err := EnrollmentByID(d, opts.EnrollmentID)
138→	if err != nil {
139→		return nil, err
140→	}
141→	if opts.MailboxID == "" {
142→		opts.MailboxID = enrollment.MailboxID
143→	}
144→	if opts.ThreadID == "" {
145→		opts.ThreadID = enrollment.ThreadID
146→	}
147→	if opts.ContactEmail == "" {
148→		opts.ContactEmail = enrollment.ContactEmail
149→	}
150→	normalizedContact := normalizeSuppressionValue("email", opts.ContactEmail)
151→	classification := normalizeReplyClassification(opts.Classification)
152→
153→	if existing, err := replyEventByMessageID(d, opts.MessageID); err == nil {
154→		return existing, nil
155→	} else if !isNotFound(err) {
156→		return nil, err
157→	}
158→
159→	tx, err := d.Begin()
160→	if err != nil {
161→		return nil, err
162→	}
163→	defer tx.Rollback()
164→
165→	replyID := newID("reply")
166→	_, err = tx.Exec(`
167→		INSERT INTO reply_events (
168→			id, enrollment_id, mailbox_id, thread_id, message_id, contact_email,
169→			classification, status, assigned_to, subject, snippet, draft_reply, handled_at, occurred_at
170→		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
171→		replyID, opts.EnrollmentID, opts.MailboxID, opts.ThreadID, opts.MessageID, normalizedContact,
172→		classification, replyStatus(classification), "", opts.Subject, opts.Snippet, "", "", opts.OccurredAt.UTC().Format(time.RFC3339),
173→	)
174→	if err != nil {
175→		return nil, err
176→	}
177→
178→	enrollmentStatus := StatusPaused
179→	statusReason := "reply:" + classification
180→	if classification == "not_interested" || classification == "unsubscribe" || classification == "bounced" {
181→		enrollmentStatus = StatusStopped
182→	}
183→
184→	_, err = tx.Exec(`
185→		UPDATE sequence_enrollments
186→		SET status = ?, status_reason = ?, reply_state = ?, last_reply_at = ?, next_due_at = '', updated_at = datetime('now')
187→		WHERE lower(contact_email) = lower(?) AND status IN (?, ?)`,
188→		enrollmentStatus, statusReason, classification, opts.OccurredAt.UTC().Format(time.RFC3339), normalizedContact, StatusActive, StatusPaused,
189→	)
190→	if err != nil {
191→		return nil, err
192→	}
193→
194→	_, err = tx.Exec(`
195→		UPDATE follow_up_tasks
196→		SET status = ?, canceled_reason = ?, updated_at = datetime('now')
197→		WHERE enrollment_id IN (
198→			SELECT id FROM sequence_enrollments WHERE lower(contact_email) = lower(?)
199→		) AND status = ?`,
200→		TaskStatusCanceled, statusReason, normalizedContact, TaskStatusOpen,
201→	)
202→	if err != nil {
203→		return nil, err
204→	}
205→
206→	if classification == "not_interested" || classification == "unsubscribe" || classification == "bounced" {
207→		if _, err := tx.Exec(`
208→			INSERT INTO suppressions (id, scope, value, reason, source)
209→			VALUES (?, 'email', ?, ?, 'reply')
210→			ON CONFLICT(scope, value) DO UPDATE SET reason = excluded.reason, source = excluded.source`,
211→			newID("sup"), normalizedContact, statusReason,
212→		); err != nil {
213→			return nil, err
214→		}
215→	}
216→	if classification == "bounced" {
217→		if _, err := tx.Exec(`
218→			UPDATE mailboxes
219→			SET last_bounce_at = ?,
220→				reputation_score = CASE
221→					WHEN reputation_score >= 15 THEN reputation_score - 15
222→					ELSE 0
223→				END,
224→				status = CASE
225→					WHEN reputation_score - 15 <= 40 THEN 'unhealthy'
226→					ELSE status
227→				END,
228→				updated_at = datetime('now')
229→			WHERE id = ?`,
230→			opts.OccurredAt.UTC().Format(time.RFC3339), opts.MailboxID,
231→		); err != nil {
232→			return nil, err
233→		}
234→		if err := maybeAutoSuppressDomainForBounces(tx, normalizedContact, statusReason, opts.OccurredAt); err != nil {
235→			return nil, err
236→		}
237→	}
238→
239→	// Referral handling: extract referred person and create contact
240→	if classification == "referral" {
241→		refEmail, refName := extractReferral(opts.Snippet)
242→		if refEmail != "" {
243→			// Store referral metadata on the reply event
244→			_, _ = tx.Exec(`UPDATE reply_events SET referred_email = ?, referred_name = ? WHERE id = ?`,
245→				refEmail, refName, replyID)
246→			// Create a new contact for the referred person
247→			refDomain := domainFromEmail(refEmail)
248→			_, _ = tx.Exec(`
249→				INSERT INTO contacts (id, source, source_id, email, name, domain, lead_status)
250→				VALUES (?, 'referral', ?, ?, ?, ?, 'referred')
251→				ON CONFLICT(source, email) DO NOTHING`,
252→				newID("con"), normalizedContact, refEmail, refName, refDomain)
253→		}
254→	}
255→
256→	if err := tx.Commit(); err != nil {
257→		return nil, err
258→	}
259→
260→	return replyEventByMessageID(d, opts.MessageID)
261→}
