304→func ListReplyEvents(d *sql.DB, limit int) ([]ReplyEvent, error) {
305→	query := `SELECT id, enrollment_id, mailbox_id, thread_id, message_id, contact_email, classification, status, assigned_to, subject, snippet, draft_reply, handled_at, occurred_at FROM reply_events ORDER BY occurred_at DESC`
306→	if limit > 0 {
307→		query += fmt.Sprintf(" LIMIT %d", limit)
308→	}
309→	rows, err := d.Query(query)
310→	if err != nil {
311→		return nil, err
312→	}
313→	defer rows.Close()
314→
315→	var items []ReplyEvent
316→	for rows.Next() {
317→		var item ReplyEvent
318→		if err := rows.Scan(&item.ID, &item.EnrollmentID, &item.MailboxID, &item.ThreadID, &item.MessageID, &item.ContactEmail, &item.Classification, &item.Status, &item.AssignedTo, &item.Subject, &item.Snippet, &item.DraftReply, &item.HandledAt, &item.OccurredAt); err != nil {
319→			return nil, err
320→		}
321→		item.NeedsAction = item.Status == "open"
322→		items = append(items, item)
323→	}
324→	return items, rows.Err()
325→}
