355→func replyEventByMessageID(d *sql.DB, messageID string) (*ReplyEvent, error) {
356→	row := d.QueryRow(`
357→		SELECT id, enrollment_id, mailbox_id, thread_id, message_id, contact_email, classification, status, assigned_to, subject, snippet, draft_reply, handled_at, occurred_at
358→		FROM reply_events
359→		WHERE message_id = ?`,
360→		messageID,
361→	)
362→	var item ReplyEvent
363→	if err := row.Scan(&item.ID, &item.EnrollmentID, &item.MailboxID, &item.ThreadID, &item.MessageID, &item.ContactEmail, &item.Classification, &item.Status, &item.AssignedTo, &item.Subject, &item.Snippet, &item.DraftReply, &item.HandledAt, &item.OccurredAt); err != nil {
364→		if err == sql.ErrNoRows {
365→			return nil, fmt.Errorf("reply event %s not found", messageID)
366→		}
367→		return nil, err
368→	}
369→	item.NeedsAction = item.Status == "open"
370→	return &item, nil
371→}
