  1→import { v } from "convex/values";
  2→import { httpAction, internalQuery, internalMutation } from "./_generated/server";
  3→import { internal } from "./_generated/api";
  4→import { callUnipileSend } from "./send";
  5→import {
  6→  isSuppressed,
  7→  countSendsForDay,
  8→  todayInTimezone,
  9→  withinSendWindow,
 10→} from "./helpers";
 11→
 12→// POST /api/send-email — single endpoint for all CLI-initiated sends
 13→//
 14→// Sync sends (sync: true): calls Unipile immediately, returns result.
 15→// Async sends (sync: false): creates task with pending status, cron picks it up.
 16→// Sequence sends: creates enrollment + future follow-up tasks + drafts.
 17→export const sendEmail = httpAction(async (ctx, request) => {
 18→  try {
 19→    const payload = await request.json();
 20→
 21→    // --- Auth ---
 22→    const authHeader = request.headers.get("Authorization");
 23→    if (!authHeader || !authHeader.startsWith("Bearer ")) {
 24→      return jsonResponse({ ok: false, error: "Missing auth token" }, 401);
 25→    }
 26→    const token = authHeader.slice(7);
 27→
 28→    const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
 29→    if (!user) {
 30→      return jsonResponse({ ok: false, error: "Invalid auth token" }, 401);
 31→    }
 32→    const userId = user._id;
 33→
 34→    // --- Validate required fields ---
 35→    const { to, subject, body, sendType, sync, taskId, sequence } = payload;
 36→
 37→    // If taskId is provided, we're sending an existing task
 38→    if (taskId) {
 39→      return await handleExistingTask(ctx, userId, taskId, payload);
 40→    }
 41→
 42→    if (!to || !subject || !body) {
 43→      return jsonResponse({ ok: false, error: "to, subject, and body are required" }, 400);
 44→    }
 45→
 46→    // --- Look up Unipile account ---
 47→    const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
 48→      userId,
 49→      provider: "GOOGLE",
 50→    });
 51→    if (!unipileAccount) {
 52→      return jsonResponse({ ok: false, error: "No connected email account. Run: nurge connect gmail" }, 400);
 53→    }
 54→    if (unipileAccount.status !== "connected") {
 55→      const msg = unipileAccount.status === "disconnected"
 56→        ? "Email account disconnected. Reconnect via nurge connect gmail"
 57→        : "Email account auth expired. Re-authenticate via nurge connect gmail";
 58→      return jsonResponse({ ok: false, error: msg }, 400);
 59→    }
 60→
 61→    // --- Resolve mailbox ---
 62→    const mailboxId = sequence?.mailboxId || null;
 63→    const mailbox = mailboxId
 64→      ? await ctx.runQuery(internal.sendApi.findMailboxById, { externalId: mailboxId })
 65→      : await ctx.runQuery(internal.sendApi.findActiveMailbox, { userId });
 66→
 67→    if (!mailbox) {
 68→      return jsonResponse({ ok: false, error: "No active mailbox found" }, 400);
 69→    }
 70→    if (mailbox.status === "auth_expired") {
 71→      return jsonResponse({ ok: false, error: "Mailbox auth expired. Re-authenticate via nurge connect gmail" }, 400);
 72→    }
 73→
 74→    // --- Suppression check ---
 75→    const suppression = await ctx.runQuery(internal.sendApi.checkSuppression, { userId, email: to });
 76→    if (suppression.suppressed) {
 77→      return jsonResponse({ ok: false, error: `Contact suppressed: ${suppression.reason}` }, 400);
 78→    }
 79→
 80→    // --- Send window + daily cap ---
 81→    const effectiveSendType = sendType || "first_touch";
 82→    if (!withinSendWindow(mailbox.sendWindowStartHour, mailbox.sendWindowEndHour, mailbox.sendWindowTimezone)) {
 83→      if (sync) {
 84→        return jsonResponse({ ok: false, error: "Outside send window" }, 400);
 85→      }
 86→      // Async: task will be picked up when window opens
 87→    }
 88→
 89→    const today = todayInTimezone(mailbox.sendWindowTimezone);
 90→    const sendCount = await ctx.runQuery(internal.sendApi.countSends, {
 91→      mailboxId: mailbox.externalId,
 92→      sendType: effectiveSendType,
 93→      day: today,
 94→    });
 95→    const capMap: Record<string, number> = {
 96→      first_touch: mailbox.firstTouchDailyCap,
 97→      follow_up: mailbox.followUpDailyCap,
 98→      reply: mailbox.replyDailyCap,
 99→    };
100→    const cap = capMap[effectiveSendType] || 0;
101→    if (cap > 0 && sendCount >= cap) {
102→      if (sync) {
103→        return jsonResponse({ ok: false, error: `Daily ${effectiveSendType} cap reached (${cap})` }, 400);
104→      }
105→    }
106→
107→    // --- Generate IDs ---
108→    const now = new Date().toISOString();
109→    const taskExternalId = `task-${Date.now()}-${randomSuffix()}`;
110→    const enrollmentExternalId = sequence ? `enr-${Date.now()}-${randomSuffix()}` : "";
111→
112→    // --- Create enrollment + future tasks if sequence ---
113→    if (sequence) {
114→      // Check for existing active enrollment
115→      const existingEnrollment = await ctx.runQuery(internal.sendApi.findActiveEnrollment, {
116→        userId,
117→        mailboxId: mailbox.externalId,
118→        contactEmail: to,
119→      });
120→      if (existingEnrollment) {
121→        return jsonResponse({
122→          ok: false,
123→          error: `${to} already has an active sequence enrollment (${existingEnrollment.externalId})`,
124→        }, 400);
125→      }
126→
127→      await ctx.runMutation(internal.sendApi.createSendEnrollment, {
128→        userId,
129→        enrollment: {
130→          externalId: enrollmentExternalId,
131→          sequenceName: sequence.sequenceName,
132→          campaignName: sequence.campaignName || "",
133→          mailboxId: mailbox.externalId,
134→          contactEmail: to,
135→          contactName: sequence.contactName || "",
136→          subject,
137→          currentStep: 1,
138→          totalSteps: 1 + (sequence.steps?.length || 0),
139→          initialBody: body,
140→          unipileAccountId: unipileAccount.unipileAccountId,
141→        },
142→        firstTask: {
143→          externalId: taskExternalId,
144→          stepNumber: 1,
145→          stepName: "first_touch",
146→          sendType: "first_touch",
147→          dueAt: now,
148→          subject,
149→          body,
150→          contactEmail: to,
151→          mailboxId: mailbox.externalId,
152→        },
153→        futureSteps: (sequence.steps || []).map((step: any, i: number) => {
154→          const stepTaskId = `task-${Date.now()}-${randomSuffix()}-s${step.stepNumber || i + 2}`;
155→          const draftId = `draft-${Date.now()}-${randomSuffix()}-s${step.stepNumber || i + 2}`;
156→          const dueDate = new Date(Date.now() + (step.delayDays || 3) * 86400000).toISOString();
157→          return {
158→            task: {
159→              externalId: stepTaskId,
160→              stepNumber: step.stepNumber || i + 2,
161→              stepName: step.stepName || `follow_up_${i + 1}`,
162→              sendType: step.sendType || "follow_up",
163→              dueAt: dueDate,
164→              subject: step.subject || subject,
165→              body: step.body || "",
166→              contactEmail: to,
167→              mailboxId: mailbox.externalId,
168→            },
169→            draft: {
170→              externalId: draftId,
171→              taskId: stepTaskId,
172→              stepNumber: step.stepNumber || i + 2,
173→              subject: step.subject || subject,
174→              body: step.body || "",
175→              channel: "email",
176→            },
177→          };
178→        }),
179→      });
180→    } else {
181→      // One-off send: create standalone task
182→      await ctx.runMutation(internal.sendApi.createStandaloneTask, {
183→        userId,
184→        task: {
185→          externalId: taskExternalId,
186→          enrollmentId: "",
187→          mailboxId: mailbox.externalId,
188→          contactEmail: to,
189→          subject,
190→          body,
191→          stepNumber: 1,
192→          sendType: effectiveSendType,
193→          dueAt: now,
194→        },
195→      });
196→    }
197→
198→    // --- Sync: send now ---
199→    if (sync) {
200→      const sendResult = await callUnipileSend({
201→        accountId: unipileAccount.unipileAccountId,
202→        to,
203→        subject,
204→        body,
205→      });
206→
207→      if (!sendResult.ok) {
208→        await ctx.runMutation(internal.sendApi.markTaskFailed, {
209→          userId,
210→          taskId: taskExternalId,
211→          error: sendResult.error,
212→          authError: sendResult.authError,
213→          mailboxId: mailbox.externalId,
214→        });
215→        return jsonResponse({ ok: false, error: sendResult.error }, 502);
216→      }
217→
218→      await ctx.runMutation(internal.sendApi.markTaskSent, {
219→        userId,
220→        taskId: taskExternalId,
221→        enrollmentId: enrollmentExternalId,
222→        mailboxId: mailbox.externalId,
223→        sendType: effectiveSendType,
224→        unipileMessageId: sendResult.messageId,
225→        providerId: sendResult.providerId,
226→      });
227→
228→      return jsonResponse({
229→        ok: true,
230→        messageId: sendResult.messageId,
231→        providerId: sendResult.providerId,
232→        taskId: taskExternalId,
233→        enrollmentId: enrollmentExternalId || undefined,
234→      });
235→    }
236→
237→    // --- Async: return queued ---
238→    return jsonResponse({
239→      ok: true,
240→      queued: true,
241→      taskId: taskExternalId,
242→      enrollmentId: enrollmentExternalId || undefined,
243→    });
244→  } catch (error: any) {
245→    console.error("sendEmail error:", error);
246→    return jsonResponse({ ok: false, error: error.message || "Internal error" }, 500);
247→  }
248→});
249→
250→// Handle sending an existing task (--task-id flow)
251→async function handleExistingTask(ctx: any, userId: string, taskId: string, payload: any) {
252→  const task = await ctx.runQuery(internal.sendApi.findTask, { externalId: taskId });
253→  if (!task) {
254→    return jsonResponse({ ok: false, error: `Task ${taskId} not found` }, 404);
255→  }
256→  if (task.userId !== userId) {
257→    return jsonResponse({ ok: false, error: "Task does not belong to this user" }, 403);
258→  }
259→  if (task.status !== "open") {
260→    return jsonResponse({ ok: false, error: `Task is ${task.status}, not open` }, 400);
261→  }
262→  if (task.sendStatus === "sent") {
263→    return jsonResponse({ ok: false, error: "Task already sent" }, 400);
264→  }
265→
266→  // Resolve Unipile account
267→  const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
268→    userId,
269→    provider: "GOOGLE",
270→  });
271→  if (!unipileAccount) {
272→    return jsonResponse({ ok: false, error: "No connected email account" }, 400);
273→  }
274→  if (unipileAccount.status !== "connected") {
275→    const msg = unipileAccount.status === "disconnected"
276→      ? "Email account disconnected. Reconnect via nurge connect gmail"
277→      : "Email account auth expired. Re-authenticate via nurge connect gmail";
278→    return jsonResponse({ ok: false, error: msg }, 400);
279→  }
280→
281→  // Use payload overrides or task defaults
282→  const to = payload.to || task.contactEmail;
283→  const subject = payload.subject || task.subject || "";
284→  const body = payload.body || task.body || "";
285→
286→  // Look up draft for latest content
287→  const draft = await ctx.runQuery(internal.sendApi.findDraft, { taskId });
288→  const finalSubject = subject || draft?.subject || "";
289→  const finalBody = body || draft?.body || "";
290→
291→  if (!finalSubject || !finalBody) {
292→    return jsonResponse({ ok: false, error: "No subject or body available for this task" }, 400);
293→  }
294→
295→  // Get enrollment for threading
296→  const enrollment = task.enrollmentId
297→    ? await ctx.runQuery(internal.sendApi.findEnrollment, { externalId: task.enrollmentId })
298→    : null;
299→
300→  const replyTo = enrollment?.unipileThreadProviderId || undefined;
301→
302→  const sendResult = await callUnipileSend({
303→    accountId: unipileAccount.unipileAccountId,
304→    to,
305→    subject: finalSubject,
306→    body: finalBody,
307→    replyTo,
308→  });
309→
310→  if (!sendResult.ok) {
311→    await ctx.runMutation(internal.sendApi.markTaskFailed, {
312→      userId,
313→      taskId,
314→      error: sendResult.error,
315→      authError: sendResult.authError,
316→      mailboxId: task.mailboxId,
317→    });
318→    return jsonResponse({ ok: false, error: sendResult.error }, 502);
319→  }
320→
321→  await ctx.runMutation(internal.sendApi.markTaskSent, {
322→    userId,
323→    taskId,
324→    enrollmentId: task.enrollmentId,
325→    mailboxId: task.mailboxId,
326→    sendType: task.sendType,
327→    unipileMessageId: sendResult.messageId,
328→    providerId: sendResult.providerId,
329→  });
330→
331→  return jsonResponse({
332→    ok: true,
333→    messageId: sendResult.messageId,
334→    providerId: sendResult.providerId,
335→    taskId,
336→    enrollmentId: task.enrollmentId || undefined,
337→  });
338→}
