type PendingDraft struct {
	ContactEmail   string `json:"contactEmail"`
	Classification string `json:"classification"`
	Status         string `json:"status"`
}

func checkPendingDrafts(d *sql.DB) ([]PendingDraft, error) {
	// Query Convex for pending drafts via the existing sync client
	// This pulls from the replyDrafts table via the sync mechanism
	// For now, check local reply_events with status='open'
	rows, err := d.Query(`
		SELECT contact_email, classification, status
		FROM reply_events
		WHERE status = 'open'
		ORDER BY occurred_at DESC
		LIMIT 10`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var drafts []PendingDraft
	for rows.Next() {
		var p PendingDraft
		if err := rows.Scan(&p.ContactEmail, &p.Classification, &p.Status); err != nil {
			return nil, err
		}
		drafts = append(drafts, p)
	}
	return drafts, rows.Err()
}
