// convex/slack.ts
//
// Slack notification and interactive message handling for reply drafts.

import { v } from "convex/values";
import { internalAction, internalMutation, internalQuery } from "./_generated/server";
import { httpAction } from "./_generated/server";
import { internal } from "./_generated/api";
import { callUnipileSend } from "./send";

const SLACK_API = "https://slack.com/api";

// Send a Slack notification for a pending reply draft.
export const notifyDraft = internalAction({
  args: { draftId: v.id("replyDrafts") },
  handler: async (ctx, args) => {
    const draft = await ctx.runQuery(internal.slack.getDraft, { draftId: args.draftId });
    if (!draft || draft.status !== "pending_review") return;

    const slackConn = await ctx.runQuery(internal.slack.getSlackConnection, {
      userId: draft.userId,
    });
    if (!slackConn || slackConn.status !== "active") return;

    // Decrypt bot token
    const keyHex = process.env.CONVEX_ENCRYPTION_KEY;
    if (!keyHex) return;
    // Use same decrypt helper as gmailApi
    const botToken = await decryptToken(slackConn.encryptedBotToken, slackConn.botTokenIv, keyHex);

    const classificationEmoji: Record<string, string> = {
      interested: "fire",
      replied: "speech_balloon",
      referral: "handshake",
      out_of_office: "palm_tree",
      objection: "thinking_face",
    };

    const emoji = classificationEmoji[draft.classification] || "incoming_envelope";
    const wordCount = (draft.draftBody || "").split(/\s+/).length;

    const blocks = [
      {
        type: "header",
        text: {
          type: "plain_text",
          text: `:${emoji}: Reply from ${draft.contactName || draft.contactEmail}`,
        },
      },
      {
        type: "section",
        text: {
          type: "mrkdwn",
          text: `*${draft.classification.toUpperCase()}*  |  ${draft.originalSubject}\n\n> ${draft.originalSnippet}`,
        },
      },
      { type: "divider" },
      {
        type: "section",
        text: {
          type: "mrkdwn",
          text: `*Draft reply* (${wordCount} words, confidence: ${draft.confidence}):\n\n${draft.draftBody}`,
        },
      },
      {
        type: "actions",
        block_id: `reply_actions_${draft._id}`,
        elements: [
          {
            type: "button",
            text: { type: "plain_text", text: "Send" },
            style: "primary",
            action_id: "approve_reply",
            value: String(draft._id),
          },
          {
            type: "button",
            text: { type: "plain_text", text: "Edit" },
            action_id: "edit_reply",
            value: String(draft._id),
          },
          {
            type: "button",
            text: { type: "plain_text", text: "Skip" },
            action_id: "skip_reply",
            value: String(draft._id),
          },
        ],
      },
    ];

    const resp = await fetch(`${SLACK_API}/chat.postMessage`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${botToken}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        channel: slackConn.channelId,
        blocks,
        text: `Reply from ${draft.contactEmail}: ${draft.originalSnippet}`, // fallback
      }),
    });

    const result = await resp.json();

    if (result.ok && result.ts) {
      await ctx.runMutation(internal.slack.markNotified, {
        draftId: args.draftId,
        slackMessageTs: result.ts,
      });
    }
  },
});

// Slack interactive callback handler
export const slackCallback = httpAction(async (ctx, request) => {
  const body = await request.formData();
  const payloadStr = body.get("payload");
  if (!payloadStr) {
    return new Response("Missing payload", { status: 400 });
  }

  const payload = JSON.parse(payloadStr as string);

  // Verify Slack signature (in production, check X-Slack-Signature header)
  // For now, validate the token matches our verification token
  const action = payload.actions?.[0];
  if (!action) {
    return new Response("No action", { status: 400 });
  }

  const draftId = action.value;

  if (action.action_id === "approve_reply") {
    // Approve and send
    const sendData = await ctx.runMutation(internal.replyDrafts.approveDraft, {
      draftId,
    });

    if (sendData) {
      // Find Unipile account and send
      const user = await ctx.runQuery(internal.sendApi.findUserByToken, {
        token: "", // Need to look up by userId from draft
      });

      // Get the draft to find userId
      const draft = await ctx.runQuery(internal.slack.getDraft, { draftId });
      if (draft) {
        const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
          userId: draft.userId,
          provider: "GOOGLE",
        });

        if (unipileAccount && unipileAccount.status === "connected") {
          const enrollment = await ctx.runQuery(internal.slack.findEnrollmentByThread, {
            userId: draft.userId,
            threadId: draft.threadId,
          });

          const sendResult = await callUnipileSend({
            accountId: unipileAccount.unipileAccountId,
            to: sendData.contactEmail,
            subject: sendData.subject,
            body: sendData.body,
            replyTo: enrollment?.unipileThreadProviderId || undefined,
          });

          if (sendResult.ok) {
            await ctx.runMutation(internal.replyDrafts.markDraftSent, { draftId });

            // Update Slack message to show sent
            // (would need bot token again - simplify by just acknowledging)
          }
        }
      }
    }

    return new Response(JSON.stringify({
      response_type: "in_channel",
      replace_original: true,
      text: `Reply sent to ${draftId}`,
    }), {
      status: 200,
      headers: { "Content-Type": "application/json" },
    });
  }

  if (action.action_id === "skip_reply") {
    await ctx.runMutation(internal.replyDrafts.rejectDraft, { draftId });
    return new Response(JSON.stringify({
      replace_original: true,
      text: "Reply skipped.",
    }), {
      status: 200,
      headers: { "Content-Type": "application/json" },
    });
  }

  if (action.action_id === "edit_reply") {
    // Open modal for editing
    const draft = await ctx.runQuery(internal.slack.getDraft, { draftId });
    if (!draft) {
      return new Response("Draft not found", { status: 404 });
    }

    // Return modal view
    return new Response(JSON.stringify({
      trigger_id: payload.trigger_id,
      view: {
        type: "modal",
        callback_id: `edit_reply_${draftId}`,
        title: { type: "plain_text", text: "Edit Reply" },
        submit: { type: "plain_text", text: "Send" },
        blocks: [
          {
            type: "input",
            block_id: "reply_body",
            element: {
              type: "plain_text_input",
              action_id: "body",
              multiline: true,
              initial_value: draft.draftBody || "",
            },
            label: { type: "plain_text", text: "Reply" },
          },
        ],
      },
    }), {
      status: 200,
      headers: { "Content-Type": "application/json" },
    });
  }

  return new Response("OK", { status: 200 });
});

// Internal queries
export const getDraft = internalQuery({
  args: { draftId: v.id("replyDrafts") },
  handler: async (ctx, args) => {
    return await ctx.db.get(args.draftId);
  },
});

export const getSlackConnection = internalQuery({
  args: { userId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("slackConnections")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
  },
});

export const markNotified = internalMutation({
  args: { draftId: v.id("replyDrafts"), slackMessageTs: v.string() },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.draftId, {
      slackMessageTs: args.slackMessageTs,
      notifiedAt: new Date().toISOString(),
    });
  },
});

export const findEnrollmentByThread = internalQuery({
  args: { userId: v.string(), threadId: v.string() },
  handler: async (ctx, args) => {
    const enrollments = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .collect();
    return enrollments.find((e) => e.threadId === args.threadId) || null;
  },
});

// Decrypt helper (shared with gmailApi)
async function decryptToken(encrypted: string, iv: string, keyHex: string): Promise<string> {
  const keyBytes = hexToBytes(keyHex);
  const ivBytes = hexToBytes(iv);
  const cipherBytes = hexToBytes(encrypted);

  const cryptoKey = await crypto.subtle.importKey(
    "raw", keyBytes, { name: "AES-GCM" }, false, ["decrypt"]
  );

  const decrypted = await crypto.subtle.decrypt(
    { name: "AES-GCM", iv: ivBytes }, cryptoKey, cipherBytes
  );

  return new TextDecoder().decode(decrypted);
}

function hexToBytes(hex: string): Uint8Array {
  const bytes = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = parseInt(hex.substring(i, i + 2), 16);
  }
  return bytes;
}
