```typescript
// convex/outcomeLearning.ts
//
// Aggregates deal outcomes into learnable patterns.
// Runs periodically to compute: which personas close, which sequences work,
// which hooks lead to revenue (not just replies).

import { v } from "convex/values";
import { internalQuery } from "./_generated/server";

// Generate outcome insights for a user
export const getOutcomeInsights = internalQuery({
  args: { userId: v.string() },
  handler: async (ctx, args) => {
    const outcomes = await ctx.db
      .query("dealOutcomes")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .collect();

    if (outcomes.length < 3) {
      return { insufficient_data: true, total: outcomes.length };
    }

    const won = outcomes.filter((o) => o.outcome === "won");
    const lost = outcomes.filter((o) => o.outcome === "lost");

    // Persona breakdown
    const byPersona: Record<string, { won: number; lost: number; avgValue: number; avgDays: number }> = {};
    for (const o of outcomes) {
      const persona = o.personaMatch || "unknown";
      if (!byPersona[persona]) byPersona[persona] = { won: 0, lost: 0, avgValue: 0, avgDays: 0 };
      if (o.outcome === "won") {
        byPersona[persona].won++;
        byPersona[persona].avgValue += o.value || 0;
        byPersona[persona].avgDays += o.daysToClose || 0;
      } else if (o.outcome === "lost") {
        byPersona[persona].lost++;
      }
    }
    for (const p of Object.keys(byPersona)) {
      if (byPersona[p].won > 0) {
        byPersona[p].avgValue /= byPersona[p].won;
        byPersona[p].avgDays /= byPersona[p].won;
      }
    }

    // Sequence breakdown
    const bySequence: Record<string, { won: number; lost: number; avgTouches: number }> = {};
    for (const o of outcomes) {
      const seq = o.sequenceName || "unknown";
      if (!bySequence[seq]) bySequence[seq] = { won: 0, lost: 0, avgTouches: 0 };
      if (o.outcome === "won") {
        bySequence[seq].won++;
        bySequence[seq].avgTouches += o.touchCount || 0;
      } else if (o.outcome === "lost") {
        bySequence[seq].lost++;
      }
    }

    // Source breakdown
    const bySource: Record<string, { won: number; lost: number }> = {};
    for (const o of outcomes) {
      const src = o.sourcedBy || "unknown";
      if (!bySource[src]) bySource[src] = { won: 0, lost: 0 };
      if (o.outcome === "won") bySource[src].won++;
      else if (o.outcome === "lost") bySource[src].lost++;
    }

    // Loss reasons
    const lossReasons: Record<string, number> = {};
    for (const o of lost) {
      const reason = o.lossReason || "unknown";
      lossReasons[reason] = (lossReasons[reason] || 0) + 1;
    }

    return {
      total: outcomes.length,
      won: won.length,
      lost: lost.length,
      winRate: won.length / (won.length + lost.length),
      avgDealValue: won.reduce((s, o) => s + (o.value || 0), 0) / (won.length || 1),
      avgDaysToClose: won.reduce((s, o) => s + (o.daysToClose || 0), 0) / (won.length || 1),
      byPersona,
      bySequence,
      bySource,
      lossReasons,
    };
  },
});
```

