```typescript
// convex/crmWebhook.ts
//
// Receives deal stage change webhooks from HubSpot.
// Extracts won/lost outcome and attribution data.

import { v } from "convex/values";
import { httpAction, internalMutation, internalQuery } from "./_generated/server";
import { internal } from "./_generated/api";

// HubSpot sends deal property changes via webhook
export const hubspotDealWebhook = httpAction(async (ctx, request) => {
  try {
    const events = await request.json();

    // HubSpot sends an array of subscription events
    for (const event of events) {
      // We only care about deal stage changes
      if (event.subscriptionType !== "deal.propertyChange" ||
          event.propertyName !== "dealstage") {
        continue;
      }

      const dealId = String(event.objectId);
      const newStage = event.propertyValue;

      // Map HubSpot stages to outcomes
      const outcome = mapHubSpotStage(newStage);
      if (!outcome) continue; // Not a terminal stage

      await ctx.runMutation(internal.crmWebhook.recordOutcome, {
        crmDealId: dealId,
        outcome,
        source: "hubspot",
      });
    }

    return new Response("OK", { status: 200 });
  } catch (error: any) {
    console.error("HubSpot webhook error:", error);
    return new Response("OK", { status: 200 }); // Always 200 to prevent retries
  }
});

function mapHubSpotStage(stage: string): string | null {
  const wonStages = ["closedwon", "closed_won", "won"];
  const lostStages = ["closedlost", "closed_lost", "lost"];

  const normalized = stage.toLowerCase().replace(/\s+/g, "");
  if (wonStages.includes(normalized)) return "won";
  if (lostStages.includes(normalized)) return "lost";
  return null;
}

// Record a deal outcome and compute attribution
export const recordOutcome = internalMutation({
  args: {
    crmDealId: v.string(),
    outcome: v.string(),
    source: v.string(),
  },
  handler: async (ctx, args) => {
    // Look up the deal in our deals table
    const deal = await ctx.db
      .query("deals")
      .filter((q) => q.eq(q.field("sourceId"), args.crmDealId))
      .first();

    if (!deal) {
      console.log(`Deal ${args.crmDealId} not found in Nurge`);
      return;
    }

    // Check if we already recorded this outcome
    const existing = await ctx.db
      .query("dealOutcomes")
      .withIndex("by_contact", (q) =>
        q.eq("userId", deal.userId).eq("contactEmail", deal.contactEmail || "")
      )
      .first();
    if (existing) return;

    // Find the enrollment that sourced this deal
    const enrollment = deal.contactEmail
      ? await ctx.db
          .query("sequenceEnrollments")
          .withIndex("by_contact", (q) =>
            q.eq("userId", deal.userId).eq("contactEmail", deal.contactEmail)
          )
          .first()
      : null;

    // Find the contact for persona info
    const contact = deal.contactEmail
      ? await ctx.db
          .query("contacts")
          .withIndex("by_email", (q) =>
            q.eq("userId", deal.userId).eq("email", deal.contactEmail)
          )
          .first()
      : null;

    // Count touches (send events for this contact's mailbox)
    let touchCount = 0;
    if (enrollment) {
      const tasks = await ctx.db
        .query("followUpTasks")
        .withIndex("by_enrollment", (q) => q.eq("enrollmentId", enrollment.externalId))
        .collect();
      touchCount = tasks.filter((t) => t.sendStatus === "sent").length;
    }

    // Calculate days to close
    const firstContact = enrollment?.lastSentAt || deal.contactEmail;
    const closeDate = deal.closeDate || new Date().toISOString();
    const daysToClose = firstContact
      ? Math.round((new Date(closeDate).getTime() - new Date(enrollment?.lastSentAt || closeDate).getTime()) / 86400000)
      : 0;

    await ctx.db.insert("dealOutcomes", {
      userId: deal.userId,
      source: args.source,
      sourceId: args.crmDealId,
      contactEmail: deal.contactEmail || "",
      company: deal.company,
      enrollmentId: enrollment?.externalId,
      outcome: args.outcome,
      value: deal.value,
      currency: deal.currency,
      lossReason: args.outcome === "lost" ? deal.stage : undefined,
      closeDate,
      detectedAt: new Date().toISOString(),
      sourcedBy: contact?.source,
      sequenceName: enrollment?.sequenceName,
      touchCount,
      daysToClose,
      personaMatch: contact?.title,
    });
  },
});
