});

// HTTP endpoint: update draft (for RemoteTrigger via curl)
export const updateDraftHttp = httpAction(async (ctx, request) => {
  const authHeader = request.headers.get("Authorization");
  if (!authHeader?.startsWith("Bearer ")) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), { status: 401 });
  }
  const token = authHeader.slice(7);

  const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
