    if (!keyHex) return;
    // Use same decrypt helper as gmailApi
    const botToken = await decryptToken(slackConn.encryptedBotToken, slackConn.botTokenIv, keyHex);

    const classificationEmoji: Record<string, string> = {
      interested: "fire",
      replied: "speech_balloon",
      referral: "handshake",
      out_of_office: "palm_tree",
      objection: "thinking_face",
    };

    const emoji = classificationEmoji[draft.classification] || "incoming_envelope";
    const wordCount = (draft.draftBody || "").split(/\s+/).length;

    const blocks = [
