// Slack interactive callback handler
export const slackCallback = httpAction(async (ctx, request) => {
  const body = await request.formData();
  const payloadStr = body.get("payload");
  if (!payloadStr) {
    return new Response("Missing payload", { status: 400 });
  }

  const payload = JSON.parse(payloadStr as string);

  // Verify Slack signature (in production, check X-Slack-Signature header)
  // For now, validate the token matches our verification token
  const action = payload.actions?.[0];
  if (!action) {
    return new Response("No action", { status: 400 });
  }

  const draftId = action.value;

  if (action.action_id === "approve_reply") {
    // Approve and send
    const sendData = await ctx.runMutation(internal.replyDrafts.approveDraft, {
      draftId,
    });

    if (sendData) {
      // Find Unipile account and send
      const user = await ctx.runQuery(internal.sendApi.findUserByToken, {
        token: "", // Need to look up by userId from draft
      });

      // Get the draft to find userId
      const draft = await ctx.runQuery(internal.slack.getDraft, { draftId });
      if (draft) {
        const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
          userId: draft.userId,
          provider: "GOOGLE",
        });

        if (unipileAccount && unipileAccount.status === "connected") {
          const enrollment = await ctx.runQuery(internal.slack.findEnrollmentByThread, {
            userId: draft.userId,
            threadId: draft.threadId,
          });

          const sendResult = await callUnipileSend({
            accountId: unipileAccount.unipileAccountId,
            to: sendData.contactEmail,
            subject: sendData.subject,
            body: sendData.body,
            replyTo: enrollment?.unipileThreadProviderId || undefined,
          });

          if (sendResult.ok) {
            await ctx.runMutation(internal.replyDrafts.markDraftSent, { draftId });

            // Update Slack message to show sent
            // (would need bot token again - simplify by just acknowledging)
          }
        }
      }
    }

    return new Response(JSON.stringify({
      response_type: "in_channel",
      replace_original: true,
      text: `Reply sent to ${draftId}`,
    }), {
      status: 200,
      headers: { "Content-Type": "application/json" },
    });
  }

  if (action.action_id === "skip_reply") {
    await ctx.runMutation(internal.replyDrafts.rejectDraft, { draftId });
    return new Response(JSON.stringify({
      replace_original: true,
      text: "Reply skipped.",
    }), {
      status: 200,
      headers: { "Content-Type": "application/json" },
    });
  }

  if (action.action_id === "edit_reply") {
    // Open modal for editing
    const draft = await ctx.runQuery(internal.slack.getDraft, { draftId });
    if (!draft) {
      return new Response("Draft not found", { status: 404 });
    }

    // Return modal view
    return new Response(JSON.stringify({
      trigger_id: payload.trigger_id,
      view: {
        type: "modal",
        callback_id: `edit_reply_${draftId}`,
        title: { type: "plain_text", text: "Edit Reply" },
        submit: { type: "plain_text", text: "Send" },
        blocks: [
          {
            type: "input",
            block_id: "reply_body",
            element: {
              type: "plain_text_input",
              action_id: "body",
              multiline: true,
              initial_value: draft.draftBody || "",
            },
            label: { type: "plain_text", text: "Reply" },
          },
        ],
      },
    }), {
      status: 200,
      headers: { "Content-Type": "application/json" },
    });
  }

  return new Response("OK", { status: 200 });
});

