// convex/gmailApi.ts
//
// Gmail API helpers for server-side reply fetching.
// Uses stored refresh token to get access token, then calls history.list
// to find new messages since the last known historyId.

import { v } from "convex/values";
import {
  internalAction,
  internalMutation,
  internalQuery,
  httpAction,
} from "./_generated/server";
import { internal } from "./_generated/api";

const GMAIL_TOKEN_URL = "https://oauth2.googleapis.com/token";
const GMAIL_API_BASE = "https://gmail.googleapis.com/gmail/v1/users/me";

// ── Crypto helpers ──────────────────────────────────────────────────

function hexToBytes(hex: string): Uint8Array {
  const bytes = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = parseInt(hex.substring(i, i + 2), 16);
  }
  return bytes;
}

function bytesToHex(bytes: Uint8Array): string {
  return Array.from(bytes)
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

async function decryptToken(
  encrypted: string,
  iv: string
): Promise<string> {
  const keyHex = process.env.CONVEX_ENCRYPTION_KEY;
  if (!keyHex) throw new Error("CONVEX_ENCRYPTION_KEY not set");

  const keyBytes = hexToBytes(keyHex);
  const ivBytes = hexToBytes(iv);
  const cipherBytes = hexToBytes(encrypted);

  const cryptoKey = await crypto.subtle.importKey(
    "raw",
    keyBytes,
    { name: "AES-GCM" },
    false,
    ["decrypt"]
  );

  const decrypted = await crypto.subtle.decrypt(
    { name: "AES-GCM", iv: ivBytes },
    cryptoKey,
    cipherBytes
  );

  return new TextDecoder().decode(decrypted);
}

export async function encryptToken(
  plaintext: string
): Promise<{ encrypted: string; iv: string }> {
  const keyHex = process.env.CONVEX_ENCRYPTION_KEY;
  if (!keyHex) throw new Error("CONVEX_ENCRYPTION_KEY not set");

  const keyBytes = hexToBytes(keyHex);
  const ivBytes = crypto.getRandomValues(new Uint8Array(12));

  const cryptoKey = await crypto.subtle.importKey(
    "raw",
    keyBytes,
    { name: "AES-GCM" },
    false,
    ["encrypt"]
  );

  const encrypted = await crypto.subtle.encrypt(
    { name: "AES-GCM", iv: ivBytes },
    cryptoKey,
    new TextEncoder().encode(plaintext)
  );

  return {
    encrypted: bytesToHex(new Uint8Array(encrypted)),
    iv: bytesToHex(ivBytes),
  };
}

// ── Gmail API helpers ───────────────────────────────────────────────

async function getAccessToken(refreshToken: string): Promise<string> {
  const clientId = process.env.GMAIL_CLIENT_ID;
  const clientSecret = process.env.GMAIL_CLIENT_SECRET;
  if (!clientId || !clientSecret) {
    throw new Error(
      "GMAIL_CLIENT_ID and GMAIL_CLIENT_SECRET env vars required"
    );
  }

  const resp = await fetch(GMAIL_TOKEN_URL, {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body: new URLSearchParams({
      client_id: clientId,
      client_secret: clientSecret,
      refresh_token: refreshToken,
      grant_type: "refresh_token",
    }),
  });

  if (!resp.ok) {
    const err = await resp.text();
    throw new Error(`Token refresh failed (${resp.status}): ${err}`);
  }

  const data = await resp.json();
  return data.access_token;
}

async function fetchHistoryMessages(
  accessToken: string,
  historyId: string
): Promise<Array<{ id: string; threadId: string }>> {
  const url = `${GMAIL_API_BASE}/history?startHistoryId=${historyId}&historyTypes=messageAdded&labelId=INBOX`;
  const resp = await fetch(url, {
    headers: { Authorization: `Bearer ${accessToken}` },
  });

  if (!resp.ok) {
    if (resp.status === 404) {
      // historyId too old, need full sync
      return [];
    }
    throw new Error(`history.list failed (${resp.status})`);
  }

  const data = await resp.json();
  const messages: Array<{ id: string; threadId: string }> = [];

  for (const record of data.history || []) {
    for (const msg of record.messagesAdded || []) {
      messages.push({
        id: msg.message.id,
        threadId: msg.message.threadId,
      });
    }
  }

  return messages;
}

async function fetchMessage(
  accessToken: string,
  messageId: string
): Promise<{
  id: string;
  threadId: string;
  from: string;
  to: string;
  subject: string;
  snippet: string;
  date: string;
  inReplyTo: string;
}> {
  const url = `${GMAIL_API_BASE}/messages/${messageId}?format=metadata&metadataHeaders=From&metadataHeaders=To&metadataHeaders=Subject&metadataHeaders=Date&metadataHeaders=In-Reply-To`;
  const resp = await fetch(url, {
    headers: { Authorization: `Bearer ${accessToken}` },
  });

  if (!resp.ok) {
    throw new Error(`messages.get failed (${resp.status})`);
  }

  const data = await resp.json();
  const headers: Record<string, string> = {};
  for (const h of data.payload?.headers || []) {
    headers[h.name.toLowerCase()] = h.value;
  }

  return {
    id: data.id,
    threadId: data.threadId,
    from: headers["from"] || "",
    to: headers["to"] || "",
    subject: headers["subject"] || "",
    snippet: data.snippet || "",
    date: headers["date"] || "",
    inReplyTo: headers["in-reply-to"] || "",
  };
}

function extractEmail(fromHeader: string): string {
  const match = fromHeader.match(/<([^>]+)>/);
  return match ? match[1].toLowerCase() : fromHeader.toLowerCase().trim();
}

// ── Main action: fetch new replies ──────────────────────────────────

export const fetchGmailReplies = internalAction({
  args: {
    email: v.string(),
    historyId: v.string(),
  },
  handler: async (ctx, args) => {
    // 1. Look up stored credentials
    const creds = await ctx.runQuery(internal.gmailApi.getCredentials, {
      email: args.email,
    });
    if (!creds || creds.status !== "active") {
      console.log(`No active Gmail credentials for ${args.email}`);
      return {
        repliesFound: 0,
        error: creds ? "credentials_" + creds.status : "no_credentials",
      };
    }

    // 2. Decrypt refresh token
    let refreshToken: string;
    try {
      refreshToken = await decryptToken(
        creds.encryptedRefreshToken,
        creds.tokenIv
      );
    } catch (e: any) {
      console.error("Failed to decrypt Gmail token:", e.message);
      await ctx.runMutation(internal.gmailApi.markCredentialsExpired, {
        email: args.email,
      });
      return { repliesFound: 0, error: "decrypt_failed" };
    }

    // 3. Get access token
    let accessToken: string;
    try {
      accessToken = await getAccessToken(refreshToken);
    } catch (e: any) {
      console.error("Gmail token refresh failed:", e.message);
      await ctx.runMutation(internal.gmailApi.markCredentialsExpired, {
        email: args.email,
      });
      return { repliesFound: 0, error: "token_refresh_failed" };
    }

    // Update lastUsedAt
    await ctx.runMutation(internal.gmailApi.touchCredentials, {
      email: args.email,
    });

    // 4. Fetch history since last historyId
    const newMessages = await fetchHistoryMessages(accessToken, args.historyId);
    if (newMessages.length === 0) {
      return { repliesFound: 0 };
    }

    // 5. For each new message, check if it's a reply to our outbound
    let repliesFound = 0;
    for (const msg of newMessages) {
      try {
        const message = await fetchMessage(accessToken, msg.id);

        // Skip messages FROM the user's own email (outbound, not inbound)
        if (
          message.from.toLowerCase().includes(args.email.toLowerCase())
        ) {
          continue;
        }

        // Only process if it's a reply (has In-Reply-To or is in a tracked thread)
        if (!message.inReplyTo && !message.threadId) {
          continue;
        }

        // Check if this thread belongs to one of our enrollments
        const enrollment = await ctx.runQuery(
          internal.gmailApi.findEnrollmentByThread,
          {
            threadId: message.threadId,
            email: args.email,
          }
        );

        if (!enrollment) {
          continue; // Not a reply to our outbound
        }

        // 6. Create reply draft via replyDrafts module
        await ctx.runMutation(internal.replyDrafts.createFromReply, {
          userId: enrollment.userId,
          enrollmentId: enrollment.externalId,
          mailboxId: enrollment.mailboxId,
          threadId: message.threadId,
          messageId: message.id,
          contactEmail: extractEmail(message.from),
          subject: message.subject,
          snippet: message.snippet,
          occurredAt: new Date().toISOString(),
        });

        repliesFound++;
      } catch (e: any) {
        console.error(`Error processing message ${msg.id}:`, e.message);
      }
    }

    return { repliesFound };
  },
});

// ── Internal queries/mutations ──────────────────────────────────────

export const getCredentials = internalQuery({
  args: { email: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("gmailCredentials")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();
  },
});

export const markCredentialsExpired = internalMutation({
  args: { email: v.string() },
  handler: async (ctx, args) => {
    const creds = await ctx.db
      .query("gmailCredentials")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();
    if (creds) {
      await ctx.db.patch(creds._id, { status: "expired" });
    }
  },
});

export const touchCredentials = internalMutation({
  args: { email: v.string() },
  handler: async (ctx, args) => {
    const creds = await ctx.db
      .query("gmailCredentials")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();
    if (creds) {
      await ctx.db.patch(creds._id, {
        lastUsedAt: new Date().toISOString(),
      });
    }
  },
});

export const findEnrollmentByThread = internalQuery({
  args: { threadId: v.string(), email: v.string() },
  handler: async (ctx, args) => {
    // Find the user by email from watch state
    const watchState = await ctx.db
      .query("gmailWatchState")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();
    if (!watchState || !watchState.userId) return null;

    // Find enrollment with this threadId
    const enrollments = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_user", (q) => q.eq("userId", watchState.userId))
      .collect();

    return (
      enrollments.find(
        (e) =>
          e.threadId === args.threadId &&
          (e.status === "active" || e.status === "paused")
      ) || null
    );
  },
});

export const upsertCredentials = internalMutation({
  args: {
    userId: v.string(),
    email: v.string(),
    encryptedRefreshToken: v.string(),
    tokenIv: v.string(),
    scopes: v.string(),
  },
  handler: async (ctx, args) => {
    const existing = await ctx.db
      .query("gmailCredentials")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, {
        encryptedRefreshToken: args.encryptedRefreshToken,
        tokenIv: args.tokenIv,
        scopes: args.scopes,
        storedAt: new Date().toISOString(),
        status: "active",
      });
    } else {
      await ctx.db.insert("gmailCredentials", {
        userId: args.userId,
        email: args.email,
        encryptedRefreshToken: args.encryptedRefreshToken,
        tokenIv: args.tokenIv,
        scopes: args.scopes,
        storedAt: new Date().toISOString(),
        status: "active",
      });
    }
  },
});

// ── HTTP endpoint: store credentials (called from CLI during connect) ──

export const storeGmailCredentialsHttp = httpAction(async (ctx, request) => {
  const authHeader = request.headers.get("Authorization");
  if (!authHeader?.startsWith("Bearer ")) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), {
      status: 401,
    });
  }
  const token = authHeader.slice(7);

  const user = await ctx.runQuery(internal.sendApi.findUserByToken, {
    token,
  });
  if (!user) {
    return new Response(JSON.stringify({ error: "Invalid token" }), {
      status: 401,
    });
  }

  const payload = await request.json();

  await ctx.runMutation(internal.gmailApi.upsertCredentials, {
    userId: user._id,
    email: payload.email,
    encryptedRefreshToken: payload.encryptedRefreshToken,
    tokenIv: payload.tokenIv,
    scopes: payload.scopes || "gmail.readonly,gmail.send",
  });

  return new Response(JSON.stringify({ ok: true }), {
    status: 200,
    headers: { "Content-Type": "application/json" },
  });
});

