// convex/replyDrafts.ts
//
// Reply draft lifecycle: create from detected reply, classify,
// accept draft from RemoteTrigger, handle approval/send.

import { v } from "convex/values";
import {
  internalMutation,
  internalQuery,
  httpAction,
} from "./_generated/server";
import { internal } from "./_generated/api";

// ── Classification (ported from internal/email/replies.go) ──────────

function classifyReply(
  fromEmail: string,
  subject: string,
  snippet: string
): string {
  const text = `${subject} ${snippet}`.toLowerCase();
  const from = fromEmail.toLowerCase();

  if (
    from.includes("mailer-daemon") ||
    from.includes("postmaster") ||
    text.includes("delivery status") ||
    text.includes("undeliverable")
  ) {
    return "bounced";
  }
  if (
    text.includes("out of office") ||
    text.includes("ooo") ||
    text.includes("away until") ||
    text.includes("auto-reply")
  ) {
    return "out_of_office";
  }
  if (
    text.includes("unsubscribe") ||
    text.includes("stop emailing") ||
    text.includes("do not contact")
  ) {
    return "unsubscribe";
  }
  if (
    text.includes("not interested") ||
    text.includes("no thanks") ||
    text.includes("remove me")
  ) {
    return "not_interested";
  }
  if (
    text.includes("yes") ||
    text.includes("sounds good") ||
    text.includes("let's chat") ||
    text.includes("happy to talk")
  ) {
    return "interested";
  }
  const referralPattern = /(reach out to|talk to|speak with|contact).*@/i;
  if (referralPattern.test(text)) {
    return "referral";
  }
  return "replied";
}

function needsDraft(classification: string): boolean {
  return ["interested", "replied", "referral", "out_of_office"].includes(
    classification
  );
}

// ── Create from detected reply ──────────────────────────────────────

export const createFromReply = internalMutation({
  args: {
    userId: v.string(),
    enrollmentId: v.string(),
    mailboxId: v.string(),
    threadId: v.string(),
    messageId: v.string(),
    contactEmail: v.string(),
    subject: v.string(),
    snippet: v.string(),
    occurredAt: v.string(),
  },
  handler: async (ctx, args) => {
    // Deduplicate: check if we already have a draft for this message
    const existing = await ctx.db
      .query("replyDrafts")
      .withIndex("by_reply_event", (q) =>
        q.eq("replyEventId", args.messageId)
      )
      .first();
    if (existing) return existing._id;

    const classification = classifyReply(
      args.contactEmail,
      args.subject,
      args.snippet
    );

    // Get sync version
    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    const version = (syncState?.lastSyncVersion ?? 0) + 1;

    // Create replyEvent in Convex (mirrors local RecordReply)
    const replyEventId = `reply-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

    await ctx.db.insert("replyEvents", {
      externalId: replyEventId,
      enrollmentId: args.enrollmentId,
      mailboxId: args.mailboxId,
      threadId: args.threadId,
      messageId: args.messageId,
      contactEmail: args.contactEmail,
      classification,
      subject: args.subject,
      snippet: args.snippet,
      occurredAt: args.occurredAt,
      syncVersion: version,
      userId: args.userId,
    });

    // Pause or stop the enrollment
    const enrollment = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_external_id", (q) =>
        q.eq("externalId", args.enrollmentId)
      )
      .first();

    if (enrollment) {
      const stopClassifications = [
        "not_interested",
        "unsubscribe",
        "bounced",
      ];
      const newStatus = stopClassifications.includes(classification)
        ? "stopped"
        : "paused";

      await ctx.db.patch(enrollment._id, {
        status: newStatus,
        statusReason: `reply:${classification}`,
        replyState: classification,
        lastReplyAt: args.occurredAt,
        nextDueAt: "",
        syncVersion: version,
      });

      // Cancel open tasks for this enrollment
      const tasks = await ctx.db
        .query("followUpTasks")
        .withIndex("by_enrollment", (q) =>
          q.eq("enrollmentId", args.enrollmentId)
        )
        .collect();
      for (const task of tasks) {
        if (task.status === "open") {
          await ctx.db.patch(task._id, {
            status: "canceled",
            canceledReason: `reply:${classification}`,
            syncVersion: version,
          });
        }
      }

      // Add suppression for stop classifications
      if (stopClassifications.includes(classification)) {
        const suppressionId = `sup-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
        await ctx.db.insert("suppressions", {
          externalId: suppressionId,
          scope: "email",
          value: args.contactEmail.toLowerCase(),
          reason: `reply:${classification}`,
          source: "reply",
          syncVersion: version,
          userId: args.userId,
        });
      }
    }

    // Update sync version
    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", {
        userId: args.userId,
        lastSyncVersion: version,
      });
    }

    // Create reply draft if classification warrants it
    if (needsDraft(classification)) {
      const expiresAt = new Date(
        Date.now() + 24 * 60 * 60 * 1000
      ).toISOString();

      await ctx.db.insert("replyDrafts", {
        userId: args.userId,
        replyEventId,
        contactEmail: args.contactEmail,
        threadId: args.threadId,
        originalSubject: args.subject,
        originalSnippet: args.snippet,
        classification,
        status: "pending_draft",
        expiresAt,
      });
    }

    return replyEventId;
  },
});

// ── Query drafts ────────────────────────────────────────────────────

export const listPendingDrafts = internalQuery({
  args: { userId: v.optional(v.string()), status: v.optional(v.string()) },
  handler: async (ctx, args) => {
    const targetStatus = args.status || "pending_draft";
    if (args.userId) {
      return await ctx.db
        .query("replyDrafts")
        .withIndex("by_status", (q) =>
          q.eq("userId", args.userId).eq("status", targetStatus)
        )
        .collect();
    }
    // All users (for RemoteTrigger scanning all pending drafts)
    const all = await ctx.db.query("replyDrafts").collect();
    return all.filter((d) => d.status === targetStatus);
  },
});

// ── Update draft with AI-generated response ─────────────────────────

export const updateDraft = internalMutation({
  args: {
    draftId: v.id("replyDrafts"),
    draftSubject: v.string(),
    draftBody: v.string(),
    draftedBy: v.string(),
    confidence: v.string(),
  },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.draftId, {
      draftSubject: args.draftSubject,
      draftBody: args.draftBody,
      draftedBy: args.draftedBy,
      confidence: args.confidence,
      status: "pending_review",
    });

    // Trigger Slack notification (Task 7 will wire this)
    await ctx.scheduler.runAfter(0, internal.slack.notifyDraft, {
      draftId: args.draftId,
    });
  },
});

// ── Approve + send ──────────────────────────────────────────────────

export const approveDraft = internalMutation({
  args: {
    draftId: v.id("replyDrafts"),
    editedBody: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    const draft = await ctx.db.get(args.draftId);
    if (!draft || draft.status !== "pending_review") return null;

    const body = args.editedBody || draft.draftBody;
    if (!body) return null;

    await ctx.db.patch(args.draftId, {
      draftBody: body,
      status: "approved",
      reviewedAt: new Date().toISOString(),
    });

    return {
      userId: draft.userId,
      contactEmail: draft.contactEmail,
      threadId: draft.threadId,
      subject: draft.draftSubject || `Re: ${draft.originalSubject}`,
      body,
    };
  },
});

export const markDraftSent = internalMutation({
  args: { draftId: v.id("replyDrafts") },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.draftId, {
      status: "sent",
      sentAt: new Date().toISOString(),
    });
  },
});

export const rejectDraft = internalMutation({
  args: { draftId: v.id("replyDrafts") },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.draftId, {
      status: "rejected",
      reviewedAt: new Date().toISOString(),
    });
  },
});

// ── Expire stale drafts (called by cron) ────────────────────────────

export const expireStaleDrafts = internalMutation({
  handler: async (ctx) => {
    const now = new Date().toISOString();
    const drafts = await ctx.db.query("replyDrafts").collect();
    let expired = 0;

    for (const draft of drafts) {
      if (
        (draft.status === "pending_draft" ||
          draft.status === "pending_review") &&
        draft.expiresAt < now
      ) {
        await ctx.db.patch(draft._id, { status: "expired" });
        expired++;
      }
    }

    if (expired > 0) {
      console.log(`Expired ${expired} stale reply drafts`);
    }
  },
});

// ── HTTP endpoints (for RemoteTrigger via curl) ─────────────────────

export const listDraftsHttp = httpAction(async (ctx, request) => {
  const authHeader = request.headers.get("Authorization");
  if (!authHeader?.startsWith("Bearer ")) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), {
      status: 401,
    });
  }
  const token = authHeader.slice(7);

  const user = await ctx.runQuery(internal.sendApi.findUserByToken, {
    token,
  });
  if (!user) {
    return new Response(JSON.stringify({ error: "Invalid token" }), {
      status: 401,
    });
  }

  const status =
    new URL(request.url).searchParams.get("status") || "pending_draft";
  const drafts = await ctx.runQuery(internal.replyDrafts.listPendingDrafts, {
    userId: user._id,
    status,
  });

  return new Response(JSON.stringify({ drafts }), {
    status: 200,
    headers: { "Content-Type": "application/json" },
  });
});

export const updateDraftHttp = httpAction(async (ctx, request) => {
  const authHeader = request.headers.get("Authorization");
  if (!authHeader?.startsWith("Bearer ")) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), {
      status: 401,
    });
  }
  const token = authHeader.slice(7);

  const user = await ctx.runQuery(internal.sendApi.findUserByToken, {
    token,
  });
  if (!user) {
    return new Response(JSON.stringify({ error: "Invalid token" }), {
      status: 401,
    });
  }

  const payload = await request.json();
  const { draftId, draftSubject, draftBody, confidence } = payload;

  await ctx.runMutation(internal.replyDrafts.updateDraft, {
    draftId,
    draftSubject,
    draftBody,
    draftedBy: "remote_trigger",
    confidence: confidence || "medium",
  });

  return new Response(JSON.stringify({ ok: true }), {
    status: 200,
    headers: { "Content-Type": "application/json" },
  });
});

