func (c *ConvexClient) EnrichCompany(token, slug string) ([]byte, error) {
	return c.enrichPost(token, "/api/enrich-company", map[string]string{"slug": slug})
}

// EnrichPerson fetches a full LinkedIn profile via Unipile.
func (c *ConvexClient) EnrichPerson(token, identifier string) ([]byte, error) {
	return c.enrichPost(token, "/api/enrich-person", map[string]string{"identifier": identifier})
}

