func (c *ConvexClient) EnrichSearch(token string, params map[string]interface{}) ([]byte, error) {
	return c.enrichPost(token, "/api/enrich-search", params)
}

func (c *ConvexClient) enrichPost(token, path string, payload interface{}) ([]byte, error) {
	body, err := json.Marshal(payload)
	if err != nil {
		return nil, fmt.Errorf("marshaling request: %w", err)
	}

	client := &http.Client{Timeout: 120 * time.Second}

	httpReq, err := http.NewRequest("POST", c.baseURL+path, bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("creating request: %w", err)
	}
	httpReq.Header.Set("Content-Type", "application/json")
	httpReq.Header.Set("Authorization", "Bearer "+token)

	resp, err := client.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("calling %s: %w", path, err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

package connector

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"os"

	"golang.org/x/oauth2"

	"github.com/usenurge/nurgesh/internal/account"
)

// PushGmailTokenToConvex encrypts the refresh token and sends it to Convex
// for server-side Gmail API access (reply detection without local machine).
func PushGmailTokenToConvex(token *oauth2.Token, email string) error {
	if token.RefreshToken == "" {
		return nil // No refresh token, skip silently
	}

	encKey := os.Getenv("CONVEX_ENCRYPTION_KEY")
	if encKey == "" {
		// Server-side features not configured, skip silently
		return nil
	}

	encrypted, iv, err := encryptAESGCM(token.RefreshToken, encKey)
	if err != nil {
		return fmt.Errorf("encrypting token: %w", err)
	}

	client := account.NewConvexClient()
	return client.Post("/api/store-gmail-credentials", map[string]string{
		"email":                 email,
		"encryptedRefreshToken": encrypted,
		"tokenIv":              iv,
		"scopes":               "gmail.readonly,gmail.send",
	})
}

func encryptAESGCM(plaintext, keyHex string) (string, string, error) {
	key, err := hex.DecodeString(keyHex)
	if err != nil {
		return "", "", fmt.Errorf("invalid key hex: %w", err)
	}
	if len(key) != 32 {
		return "", "", fmt.Errorf("key must be 32 bytes (64 hex chars), got %d", len(key))
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		return "", "", err
	}

	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return "", "", err
	}

	iv := make([]byte, aesGCM.NonceSize())
	if _, err := rand.Read(iv); err != nil {
		return "", "", err
	}

	ciphertext := aesGCM.Seal(nil, iv, []byte(plaintext), nil)

	return hex.EncodeToString(ciphertext), hex.EncodeToString(iv), nil
}

